-- Name: activate_payment_method_on_signature(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.activate_payment_method_on_signature() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.mandate_signed_at IS NOT NULL AND OLD.mandate_signed_at IS NULL THEN
    NEW.status = 'active';
    NEW.activated_at = NEW.mandate_signed_at;
    NEW.is_verified = TRUE;
    NEW.verification_method = 'emandate';
    NEW.mandate_active = TRUE;
  END IF;
  RETURN NEW;
END;
$$;


