--
-- Name: aggregate_demand_by_ward(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aggregate_demand_by_ward(p_days integer DEFAULT 30) RETURNS TABLE(ward_code text, check_count bigint, checks_with_coverage bigint, checks_no_coverage bigint, unique_sessions bigint)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT
    nearest_ward.ward_code,
    COUNT(*)::BIGINT AS check_count,
    COUNT(*) FILTER (WHERE ccl.has_coverage = TRUE)::BIGINT AS checks_with_coverage,
    COUNT(*) FILTER (WHERE ccl.has_coverage = FALSE)::BIGINT AS checks_no_coverage,
    COUNT(DISTINCT ccl.session_id)::BIGINT AS unique_sessions
  FROM coverage_check_logs ccl
  CROSS JOIN LATERAL (
    SELECT wd.ward_code
    FROM ward_demographics wd
    WHERE wd.centroid_lat IS NOT NULL
      AND wd.centroid_lng IS NOT NULL
    ORDER BY ST_Distance(
      ST_SetSRID(ST_MakePoint(ccl.longitude, ccl.latitude), 4326)::GEOGRAPHY,
      ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY
    )
    LIMIT 1
  ) nearest_ward
  WHERE ccl.latitude IS NOT NULL
    AND ccl.longitude IS NOT NULL
    AND ccl.created_at >= NOW() - (p_days || ' days')::INTERVAL
  GROUP BY nearest_ward.ward_code;
$$;


--
-- Name: approve_admin_access_request(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.approve_admin_access_request(p_request_id uuid, p_password text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_request pending_admin_users;
  v_user_id UUID;
  v_auth_user_id UUID;
BEGIN
  -- Get the pending request
  SELECT * INTO v_request
  FROM pending_admin_users
  WHERE id = p_request_id
  AND status = 'pending';

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Request not found or already processed'
    );
  END IF;

  -- Create Supabase Auth user
  -- Note: This needs to be called from Edge Function with service role
  -- Here we just mark as approved and return the info

  -- Update request status
  UPDATE pending_admin_users
  SET
    status = 'approved',
    reviewed_by = auth.uid(),
    reviewed_at = NOW()
  WHERE id = p_request_id;

  -- Return success with user details
  RETURN jsonb_build_object(
    'success', true,
    'email', v_request.email,
    'full_name', v_request.full_name,
    'role', v_request.requested_role
  );
END;
$$;


--
-- Name: audit_invoice_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.audit_invoice_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    action_type TEXT;
    prev_data JSONB;
    new_data_val JSONB;
BEGIN
    IF TG_OP = 'INSERT' THEN
        action_type := 'created';
        prev_data := NULL;
        new_data_val := to_jsonb(NEW);
    ELSIF TG_OP = 'UPDATE' THEN
        IF NEW.status IS DISTINCT FROM OLD.status THEN
            action_type := 'status_changed';
        ELSIF NEW.voided_at IS NOT NULL AND OLD.voided_at IS NULL THEN
            action_type := 'voided';
        ELSIF NEW.emailed_at IS DISTINCT FROM OLD.emailed_at THEN
            action_type := 'emailed';
        ELSE
            action_type := 'updated';
        END IF;
        prev_data := to_jsonb(OLD);
        new_data_val := to_jsonb(NEW);
    END IF;
    
    INSERT INTO public.invoice_audit_log (
        invoice_id,
        action,
        previous_status,
        new_status,
        previous_data,
        new_data,
        performed_by,
        created_at
    ) VALUES (
        COALESCE(NEW.id, OLD.id),
        action_type,
        OLD.status,
        NEW.status,
        prev_data,
        new_data_val,
        auth.uid(),
        NOW()
    );
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: calculate_margin_commission(numeric, numeric, integer, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_margin_commission(p_monthly_revenue numeric, p_monthly_cost numeric, p_contract_term_months integer DEFAULT 24, p_margin_share_rate numeric DEFAULT 20.00) RETURNS TABLE(monthly_revenue numeric, monthly_cost numeric, monthly_margin numeric, margin_percentage numeric, margin_share_rate numeric, monthly_commission numeric, contract_term integer, total_contract_revenue numeric, total_commission numeric, total_commission_incl_vat numeric)
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public'
    AS $$
DECLARE
  v_monthly_margin DECIMAL;
  v_margin_percentage DECIMAL;
  v_monthly_commission DECIMAL;
  v_total_commission DECIMAL;
BEGIN
  -- Calculate monthly margin
  v_monthly_margin := p_monthly_revenue - p_monthly_cost;

  -- Calculate margin percentage
  v_margin_percentage := (v_monthly_margin / p_monthly_revenue) * 100;

  -- Calculate monthly commission
  v_monthly_commission := v_monthly_margin * (p_margin_share_rate / 100);

  -- Calculate total over contract term
  v_total_commission := v_monthly_commission * p_contract_term_months;

  RETURN QUERY
  SELECT
    p_monthly_revenue,
    p_monthly_cost,
    v_monthly_margin,
    v_margin_percentage,
    p_margin_share_rate,
    v_monthly_commission,
    p_contract_term_months,
    p_monthly_revenue * p_contract_term_months AS total_contract_revenue,
    v_total_commission,
    v_total_commission * 1.15 AS total_commission_incl_vat;
END;
$$;


--
-- Name: FUNCTION calculate_margin_commission(p_monthly_revenue numeric, p_monthly_cost numeric, p_contract_term_months integer, p_margin_share_rate numeric); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calculate_margin_commission(p_monthly_revenue numeric, p_monthly_cost numeric, p_contract_term_months integer, p_margin_share_rate numeric) IS 'Calculate partner commission based on gross margin sharing model (default 20%)';


--
-- Name: calculate_mtn_dealer_commission(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_mtn_dealer_commission(p_deal_id text, p_quantity integer DEFAULT 1) RETURNS TABLE(deal_id text, price_plan text, contract_term integer, monthly_subscription numeric, total_contract_value numeric, mtn_commission_rate numeric, mtn_commission_to_arlan numeric, circletel_share_rate numeric, circletel_commission numeric, circletel_commission_incl_vat numeric, quantity integer, total_circletel_commission numeric)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    p.deal_id,
    p.price_plan,
    p.contract_term,
    p.mtn_price_incl_vat AS monthly_subscription,
    (p.mtn_price_incl_vat * p.contract_term) AS total_contract_value,
    p.mtn_commission_rate,
    (p.mtn_price_incl_vat * p.contract_term * p.mtn_commission_rate / 100) AS mtn_commission_to_arlan,
    p.circletel_commission_share AS circletel_share_rate,
    (p.mtn_price_incl_vat * p.contract_term * p.mtn_commission_rate / 100 * p.circletel_commission_share / 100) AS circletel_commission,
    (p.mtn_price_incl_vat * p.contract_term * p.mtn_commission_rate / 100 * p.circletel_commission_share / 100 * 1.15) AS circletel_commission_incl_vat,
    p_quantity AS quantity,
    (p.mtn_price_incl_vat * p.contract_term * p.mtn_commission_rate / 100 * p.circletel_commission_share / 100 * p_quantity) AS total_circletel_commission
  FROM mtn_dealer_products p
  WHERE p.deal_id = p_deal_id;
END;
$$;


--
-- Name: calculate_price_change_metrics(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_price_change_metrics() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Calculate price difference
  NEW.price_difference := NEW.new_price - NEW.old_price;

  -- Calculate percentage change (avoid division by zero)
  IF NEW.old_price > 0 THEN
    NEW.percentage_change := ROUND(
      ((NEW.new_price - NEW.old_price) / NEW.old_price * 100)::numeric,
      2
    );
  ELSE
    NEW.percentage_change := 0;
  END IF;

  -- Update updated_at timestamp
  NEW.updated_at := NOW();

  RETURN NEW;
END;
$$;


--
-- Name: calculate_product_commission(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_product_commission(p_product_sku text, p_contract_term_months integer DEFAULT 24) RETURNS TABLE(product_name text, commission_model text, monthly_revenue numeric, monthly_cost numeric, monthly_margin numeric, margin_percentage numeric, commission_rate numeric, monthly_commission numeric, total_commission numeric, total_commission_incl_vat numeric)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_product RECORD;
  v_margin_result RECORD;
  v_tiered_result RECORD;
BEGIN
  -- Get product configuration
  SELECT *
  INTO v_product
  FROM product_commission_config
  WHERE product_sku = p_product_sku
    AND is_active = true
    AND (effective_from IS NULL OR effective_from <= CURRENT_DATE)
    AND (effective_to IS NULL OR effective_to >= CURRENT_DATE)
  LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Product SKU not found or inactive: %', p_product_sku;
  END IF;

  -- Calculate based on commission model
  IF v_product.commission_model = 'margin_share' THEN
    -- Use margin-share calculation
    SELECT *
    INTO v_margin_result
    FROM calculate_margin_commission(
      v_product.monthly_price,
      v_product.monthly_cost,
      p_contract_term_months,
      v_product.margin_share_rate
    );

    RETURN QUERY
    SELECT
      v_product.product_name,
      v_product.commission_model,
      v_margin_result.monthly_revenue,
      v_margin_result.monthly_cost,
      v_margin_result.monthly_margin,
      v_margin_result.margin_percentage,
      v_margin_result.margin_share_rate AS commission_rate,
      v_margin_result.monthly_commission,
      v_margin_result.total_commission,
      v_margin_result.total_commission_incl_vat;

  ELSIF v_product.commission_model = 'tiered_revenue' THEN
    -- Use tiered calculation (MTN Arlan model)
    SELECT *
    INTO v_tiered_result
    FROM calculate_tiered_commission(
      v_product.monthly_price,
      p_contract_term_months
    );

    RETURN QUERY
    SELECT
      v_product.product_name,
      v_product.commission_model,
      v_tiered_result.monthly_value AS monthly_revenue,
      NULL::DECIMAL AS monthly_cost,
      NULL::DECIMAL AS monthly_margin,
      v_tiered_result.effective_rate AS margin_percentage,
      v_tiered_result.effective_rate AS commission_rate,
      v_tiered_result.partner_commission / p_contract_term_months AS monthly_commission,
      v_tiered_result.partner_commission AS total_commission,
      v_tiered_result.partner_commission_incl_vat AS total_commission_incl_vat;

  ELSIF v_product.commission_model = 'flat_rate' THEN
    -- Flat rate of revenue
    RETURN QUERY
    SELECT
      v_product.product_name,
      v_product.commission_model,
      v_product.monthly_price,
      v_product.monthly_cost,
      NULL::DECIMAL AS monthly_margin,
      NULL::DECIMAL AS margin_percentage,
      v_product.flat_commission_rate AS commission_rate,
      (v_product.monthly_price * v_product.flat_commission_rate / 100) AS monthly_commission,
      (v_product.monthly_price * p_contract_term_months * v_product.flat_commission_rate / 100) AS total_commission,
      (v_product.monthly_price * p_contract_term_months * v_product.flat_commission_rate / 100 * 1.15) AS total_commission_incl_vat;

  END IF;
END;
$$;


--
-- Name: FUNCTION calculate_product_commission(p_product_sku text, p_contract_term_months integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calculate_product_commission(p_product_sku text, p_contract_term_months integer) IS 'Universal commission calculator that automatically applies correct model based on product SKU';


--
-- Name: calculate_provider_avg_response_time_24h(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_provider_avg_response_time_24h(p_provider_id uuid) RETURNS integer
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  avg_time INTEGER;
BEGIN
  SELECT COALESCE(AVG(response_time_ms)::INTEGER, 0) INTO avg_time
  FROM provider_api_logs
  WHERE provider_id = p_provider_id
    AND created_at >= NOW() - INTERVAL '24 hours'
    AND success = true
    AND response_time_ms IS NOT NULL;

  RETURN avg_time;
END;
$$;


--
-- Name: FUNCTION calculate_provider_avg_response_time_24h(p_provider_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calculate_provider_avg_response_time_24h(p_provider_id uuid) IS 'Calculates average API response time over last 24 hours (successful requests only)';


--
-- Name: calculate_provider_success_rate_24h(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_provider_success_rate_24h(p_provider_id uuid) RETURNS numeric
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  total_requests INTEGER;
  successful_requests INTEGER;
  success_rate DECIMAL(5, 2);
BEGIN
  -- Count total requests in last 24 hours
  SELECT COUNT(*) INTO total_requests
  FROM provider_api_logs
  WHERE provider_id = p_provider_id
    AND created_at >= NOW() - INTERVAL '24 hours';

  -- If no requests, return 0
  IF total_requests = 0 THEN
    RETURN 0.00;
  END IF;

  -- Count successful requests
  SELECT COUNT(*) INTO successful_requests
  FROM provider_api_logs
  WHERE provider_id = p_provider_id
    AND created_at >= NOW() - INTERVAL '24 hours'
    AND success = true;

  -- Calculate percentage
  success_rate := (successful_requests::DECIMAL / total_requests::DECIMAL) * 100;

  RETURN ROUND(success_rate, 2);
END;
$$;


--
-- Name: FUNCTION calculate_provider_success_rate_24h(p_provider_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calculate_provider_success_rate_24h(p_provider_id uuid) IS 'Calculates provider API success rate over last 24 hours';


--
-- Name: calculate_quote_totals(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_quote_totals() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  items_monthly DECIMAL(10,2);
  items_installation DECIMAL(10,2);
  discount_amount DECIMAL(10,2);
BEGIN
  -- Sum all line items
  SELECT
    COALESCE(SUM(monthly_price * quantity), 0),
    COALESCE(SUM(installation_price * quantity), 0)
  INTO items_monthly, items_installation
  FROM business_quote_items
  WHERE quote_id = NEW.id;

  -- Apply discount
  IF NEW.custom_discount_percent > 0 THEN
    discount_amount := items_monthly * (NEW.custom_discount_percent / 100);
  ELSIF NEW.custom_discount_amount > 0 THEN
    discount_amount := NEW.custom_discount_amount;
  ELSE
    discount_amount := 0;
  END IF;

  -- Calculate totals
  NEW.subtotal_monthly := items_monthly;
  NEW.subtotal_installation := items_installation;
  NEW.custom_discount_amount := discount_amount;
  NEW.vat_amount_monthly := (items_monthly - discount_amount) * 0.15;
  NEW.vat_amount_installation := items_installation * 0.15;
  NEW.total_monthly := (items_monthly - discount_amount) * 1.15;
  NEW.total_installation := items_installation * 1.15;

  RETURN NEW;
END;
$$;


--
-- Name: calculate_rfi_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_rfi_status() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  passed_count INTEGER;
BEGIN
  passed_count := 0;
  IF NEW.has_rack_facility THEN passed_count := passed_count + 1; END IF;
  IF NEW.has_access_control THEN passed_count := passed_count + 1; END IF;
  IF NEW.has_air_conditioning THEN passed_count := passed_count + 1; END IF;
  IF NEW.has_ac_power THEN passed_count := passed_count + 1; END IF;

  IF passed_count = 4 THEN
    NEW.rfi_status := 'ready';
  ELSIF passed_count = 0 THEN
    NEW.rfi_status := 'not_ready';
  ELSE
    NEW.rfi_status := 'pending';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: calculate_tiered_commission(numeric, integer, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_tiered_commission(p_monthly_subscription numeric, p_contract_term_months integer DEFAULT 24, p_transaction_date date DEFAULT CURRENT_DATE) RETURNS TABLE(tier_id uuid, tier_name text, tier_order integer, base_rate numeric, partner_share_rate numeric, effective_rate numeric, monthly_value numeric, contract_term integer, total_contract_value numeric, base_commission numeric, partner_commission numeric, partner_commission_incl_vat numeric)
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public'
    AS $$
DECLARE
  v_tier RECORD;
  v_total_value DECIMAL;
  v_base_commission DECIMAL;
  v_partner_commission DECIMAL;
BEGIN
  -- Calculate total contract value
  v_total_value := p_monthly_subscription * p_contract_term_months;

  -- Find applicable tier
  SELECT *
  INTO v_tier
  FROM commission_tier_config
  WHERE is_active = true
    AND p_monthly_subscription >= min_monthly_value
    AND (max_monthly_value IS NULL OR p_monthly_subscription <= max_monthly_value)
    AND (effective_from IS NULL OR effective_from <= p_transaction_date)
    AND (effective_to IS NULL OR effective_to >= p_transaction_date)
  ORDER BY tier_order DESC
  LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'No commission tier found for monthly subscription value: %', p_monthly_subscription;
  END IF;

  -- Calculate commissions
  v_base_commission := v_total_value * (v_tier.base_commission_rate / 100);
  v_partner_commission := v_base_commission * (v_tier.partner_share_rate / 100);

  RETURN QUERY
  SELECT
    v_tier.id,
    v_tier.tier_name,
    v_tier.tier_order,
    v_tier.base_commission_rate,
    v_tier.partner_share_rate,
    v_tier.effective_rate,
    p_monthly_subscription,
    p_contract_term_months,
    v_total_value,
    v_base_commission,
    v_partner_commission,
    v_partner_commission * 1.15 AS partner_commission_incl_vat;
END;
$$;


--
-- Name: FUNCTION calculate_tiered_commission(p_monthly_subscription numeric, p_contract_term_months integer, p_transaction_date date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.calculate_tiered_commission(p_monthly_subscription numeric, p_contract_term_months integer, p_transaction_date date) IS 'Calculate partner commission based on tiered rate structure using monthly subscription value and contract term';


--
-- Name: calculate_zoho_books_next_retry(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_zoho_books_next_retry(retry_count integer) RETURNS timestamp with time zone
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN NOW() + CASE retry_count
    WHEN 0 THEN INTERVAL '5 minutes'
    WHEN 1 THEN INTERVAL '15 minutes'
    WHEN 2 THEN INTERVAL '1 hour'
    WHEN 3 THEN INTERVAL '4 hours'
    WHEN 4 THEN INTERVAL '24 hours'
    ELSE INTERVAL '24 hours'
  END;
END;
$$;


--
-- Name: check_ai_rate_limit(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_ai_rate_limit(target_user_id uuid DEFAULT auth.uid(), daily_limit integer DEFAULT 100, hourly_limit integer DEFAULT 20) RETURNS TABLE(within_limits boolean, daily_count bigint, hourly_count bigint, daily_remaining integer, hourly_remaining integer)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  WITH daily_usage AS (
    SELECT COUNT(*) as count
    FROM public.ai_usage_logs
    WHERE user_id = target_user_id
      AND created_at >= CURRENT_DATE
      AND success = true
  ),
  hourly_usage AS (
    SELECT COUNT(*) as count
    FROM public.ai_usage_logs
    WHERE user_id = target_user_id
      AND created_at >= NOW() - INTERVAL '1 hour'
      AND success = true
  )
  SELECT
    (daily_usage.count < daily_limit AND hourly_usage.count < hourly_limit) as within_limits,
    daily_usage.count::BIGINT as daily_count,
    hourly_usage.count::BIGINT as hourly_count,
    GREATEST(0, daily_limit - daily_usage.count::INTEGER) as daily_remaining,
    GREATEST(0, hourly_limit - hourly_usage.count::INTEGER) as hourly_remaining
  FROM daily_usage, hourly_usage;
$$;


--
-- Name: FUNCTION check_ai_rate_limit(target_user_id uuid, daily_limit integer, hourly_limit integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.check_ai_rate_limit(target_user_id uuid, daily_limit integer, hourly_limit integer) IS 'Checks if user has exceeded AI generation rate limits (default: 100/day, 20/hour)';


--
-- Name: check_coverage_at_point(numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_coverage_at_point(lat numeric, lng numeric) RETURNS TABLE(service_type text, coverage_quality text, speed_tier text, coverage_name text, activation_days integer)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ca.service_type,
    COALESCE(ca.coverage_quality, 'good') as coverage_quality,
    'Multiple speeds available' as speed_tier,
    COALESCE(ca.coverage_name, ca.area_name) as coverage_name,
    ca.activation_days
  FROM coverage_areas ca
  WHERE ca.status = 'active'
  -- Simple point-in-polygon check using JSONB
  -- This is a simplified implementation - in production you'd want proper PostGIS
  ORDER BY
    CASE ca.service_type
      WHEN 'BizFibreConnect' THEN 1
      WHEN 'HomeFibreConnect' THEN 2
      WHEN 'SkyFibre' THEN 3
    END;
END;
$$;


--
-- Name: check_pb_rate_limit(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_pb_rate_limit(target_user_id uuid, hourly_limit integer DEFAULT 20) RETURNS TABLE(within_limits boolean, hourly_count bigint, remaining integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COUNT(*) < hourly_limit,
    COUNT(*),
    GREATEST(hourly_limit - COUNT(*)::INTEGER, 0)
  FROM pb_ai_usage
  WHERE user_id = target_user_id
    AND created_at > NOW() - INTERVAL '1 hour'
    AND success = true;
END;
$$;


