--
-- Name: count_base_stations_in_radius(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.count_base_stations_in_radius(p_lat double precision, p_lng double precision, p_radius_km double precision) RETURNS TABLE(station_count integer, total_connections integer)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT COUNT(*)::INTEGER, COALESCE(SUM(t.active_connections), 0)::INTEGER
  FROM tarana_base_stations t
  WHERE ST_DWithin(
    ST_SetSRID(ST_MakePoint(t.lng, t.lat), 4326)::geography,
    ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
    p_radius_km * 1000
  );
$$;


--
-- Name: count_dfa_buildings_in_radius(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.count_dfa_buildings_in_radius(p_lat double precision, p_lng double precision, p_radius_km double precision) RETURNS TABLE(connected_count integer, near_net_count integer)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT
    COUNT(*) FILTER (WHERE d.coverage_type = 'connected')::INTEGER,
    COUNT(*) FILTER (WHERE d.coverage_type = 'near-net')::INTEGER
  FROM dfa_buildings d
  WHERE ST_DWithin(
    ST_SetSRID(ST_MakePoint(d.longitude, d.latitude), 4326)::geography,
    ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
    p_radius_km * 1000
  );
$$;


--
-- Name: create_approval_deadline_reminder(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_approval_deadline_reminder() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Only create reminder if deadline is set and assigned to someone
  IF NEW.approval_deadline IS NOT NULL AND NEW.assigned_to IS NOT NULL THEN
    INSERT INTO reminders (
      user_id,
      title,
      description,
      due_date,
      reminder_type,
      related_entity_type,
      related_entity_id,
      notify_in_app
    ) VALUES (
      NEW.assigned_to,
      format('Product Approval Deadline: %s', NEW.product_name),
      format('This product approval is due on %s', NEW.approval_deadline::DATE),
      NEW.approval_deadline - INTERVAL '1 day', -- Remind 1 day before
      'one_time',
      'product_approval',
      NEW.id,
      TRUE
    );
  END IF;

  RETURN NEW;
END;
$$;


