-- Name: create_coverage_lead(text, numeric, numeric, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, text, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_coverage_lead(p_address text, p_latitude numeric DEFAULT NULL::numeric, p_longitude numeric DEFAULT NULL::numeric, p_status character varying DEFAULT 'pending'::character varying, p_source character varying DEFAULT 'coverage_check'::character varying, p_customer_type character varying DEFAULT 'residential'::character varying, p_company_name character varying DEFAULT NULL::character varying, p_company_size character varying DEFAULT NULL::character varying, p_property_type character varying DEFAULT NULL::character varying, p_phone_number character varying DEFAULT NULL::character varying, p_utm_source character varying DEFAULT NULL::character varying, p_utm_medium character varying DEFAULT NULL::character varying, p_utm_campaign character varying DEFAULT NULL::character varying, p_referrer_url text DEFAULT NULL::text, p_session_id character varying DEFAULT NULL::character varying) RETURNS TABLE(id uuid, session_id character varying)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  INSERT INTO coverage_leads (
    address,
    latitude,
    longitude,
    status,
    source,
    customer_type,
    company_name,
    company_size,
    property_type,
    phone_number,
    utm_source,
    utm_medium,
    utm_campaign,
    referrer_url,
    session_id,
    created_at
  ) VALUES (
    p_address,
    p_latitude,
    p_longitude,
    p_status,
    p_source,
    p_customer_type,
    p_company_name,
    p_company_size,
    p_property_type,
    p_phone_number,
    p_utm_source,
    p_utm_medium,
    p_utm_campaign,
    p_referrer_url,
    COALESCE(p_session_id, 'session_' || extract(epoch from now())::text || '_' || substr(md5(random()::text), 1, 9)),
    NOW()
  )
  RETURNING coverage_leads.id, coverage_leads.session_id;
END;
$$;


