--
-- Name: create_margin_commission(uuid, uuid, uuid, text, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_margin_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_product_sku text, p_contract_term_months integer, p_description text) RETURNS uuid
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_transaction_id UUID;
  v_commission RECORD;
  v_product RECORD;
BEGIN
  -- Get product config
  SELECT *
  INTO v_product
  FROM product_commission_config
  WHERE product_sku = p_product_sku
    AND is_active = true
  LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Product SKU not found: %', p_product_sku;
  END IF;

  -- Calculate commission
  SELECT *
  INTO v_commission
  FROM calculate_product_commission(
    p_product_sku,
    p_contract_term_months
  );

  -- Insert transaction
  INSERT INTO partner_commission_transactions (
    partner_id,
    lead_id,
    order_id,
    product_sku,
    product_commission_config_id,
    commission_model,
    transaction_type,
    monthly_subscription_value,
    contract_term_months,
    total_contract_value,
    commission_rate,
    amount,
    status,
    description
  ) VALUES (
    p_partner_id,
    p_lead_id,
    p_order_id,
    p_product_sku,
    v_product.id,
    v_product.commission_model,
    'margin_share',
    v_product.monthly_price,
    p_contract_term_months,
    v_product.monthly_price * p_contract_term_months,
    v_commission.commission_rate,
    v_commission.total_commission,
    'pending',
    p_description || ' (' || v_product.product_name || ')'
  )
  RETURNING id INTO v_transaction_id;

  RETURN v_transaction_id;
END;
$$;


--
-- Name: FUNCTION create_margin_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_product_sku text, p_contract_term_months integer, p_description text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_margin_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_product_sku text, p_contract_term_months integer, p_description text) IS 'Create commission transaction for margin-share products (BizFibre/SkyFibre)';


--
-- Name: create_product_import_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_product_import_notification() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_product_managers UUID[];
BEGIN
  -- Get all users with product management permissions
  SELECT ARRAY_AGG(id) INTO v_product_managers
  FROM admin_users
  WHERE role_template_id IN (
    SELECT id FROM role_templates
    WHERE name IN ('Super Admin', 'Product Manager', 'Admin')
  );

  -- Create notification for each product manager
  INSERT INTO notifications (user_id, title, message, type, category, related_entity_type, related_entity_id, action_url, action_label)
  SELECT
    unnest(v_product_managers),
    'New Product Import Ready for Review',
    format('A new product import from %s with %s products is ready for your review.', NEW.product_category, NEW.total_products),
    'info',
    'product_approval',
    'product_import',
    NEW.id,
    format('/admin/products/approvals/%s', NEW.id),
    'Review Products';

  RETURN NEW;
END;
$$;


--
-- Name: create_quote_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_quote_version() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  next_version INTEGER;
  quote_snapshot JSONB;
BEGIN
  -- Only create version on status changes or pricing changes
  IF (TG_OP = 'UPDATE' AND (
    OLD.status IS DISTINCT FROM NEW.status OR
    OLD.total_monthly IS DISTINCT FROM NEW.total_monthly OR
    OLD.custom_discount_percent IS DISTINCT FROM NEW.custom_discount_percent
  )) THEN

    -- Get next version number
    SELECT COALESCE(MAX(version_number), 0) + 1
    INTO next_version
    FROM business_quote_versions
    WHERE quote_id = NEW.id;

    -- Create snapshot
    SELECT jsonb_build_object(
      'quote', row_to_json(NEW),
      'items', (
        SELECT jsonb_agg(row_to_json(i))
        FROM business_quote_items i
        WHERE i.quote_id = NEW.id
      )
    ) INTO quote_snapshot;

    -- Insert version
    INSERT INTO business_quote_versions (
      quote_id,
      version_number,
      quote_data,
      changed_by,
      change_summary
    ) VALUES (
      NEW.id,
      next_version,
      quote_snapshot,
      NEW.updated_by,
      'Status: ' || OLD.status || ' → ' || NEW.status
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: create_subscriber_diagnostics_record(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_subscriber_diagnostics_record() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
    IF NEW.connection_id IS NOT NULL AND NEW.connection_id != '' THEN
        INSERT INTO public.subscriber_diagnostics (
            customer_service_id,
            interstellio_subscriber_id,
            health_status,
            health_score
        )
        VALUES (
            NEW.id,
            NEW.connection_id,
            'unknown',
            100
        )
        ON CONFLICT (customer_service_id) DO UPDATE SET
            interstellio_subscriber_id = EXCLUDED.interstellio_subscriber_id,
            updated_at = NOW();
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: create_tiered_commission(uuid, uuid, uuid, numeric, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_tiered_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_monthly_subscription numeric, p_contract_term_months integer, p_description text) RETURNS uuid
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_transaction_id UUID;
  v_commission RECORD;
BEGIN
  -- Calculate commission using tier function
  SELECT *
  INTO v_commission
  FROM calculate_tiered_commission(
    p_monthly_subscription,
    p_contract_term_months
  );

  -- Insert transaction
  INSERT INTO partner_commission_transactions (
    partner_id,
    lead_id,
    order_id,
    transaction_type,
    monthly_subscription_value,
    contract_term_months,
    total_contract_value,
    commission_tier_id,
    base_commission_rate,
    effective_commission_rate,
    commission_rate,
    amount,
    status,
    description
  ) VALUES (
    p_partner_id,
    p_lead_id,
    p_order_id,
    'lead_conversion',
    v_commission.monthly_value,
    v_commission.contract_term,
    v_commission.total_contract_value,
    v_commission.tier_id,
    v_commission.base_rate,
    v_commission.effective_rate,
    v_commission.effective_rate, -- For compatibility with existing column
    v_commission.partner_commission,
    'pending',
    p_description || ' (' || v_commission.tier_name || ')'
  )
  RETURNING id INTO v_transaction_id;

  RETURN v_transaction_id;
END;
$$;


--
-- Name: FUNCTION create_tiered_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_monthly_subscription numeric, p_contract_term_months integer, p_description text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_tiered_commission(p_partner_id uuid, p_lead_id uuid, p_order_id uuid, p_monthly_subscription numeric, p_contract_term_months integer, p_description text) IS 'Create a commission transaction using tiered rate calculation';


--
-- Name: detect_suspicious_activity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.detect_suspicious_activity() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_recent_failures INTEGER;
  v_different_ips INTEGER;
BEGIN
  -- Check for multiple failures from same user in last 15 minutes
  SELECT COUNT(*)
  INTO v_recent_failures
  FROM admin_audit_logs
  WHERE user_email = NEW.user_email
    AND status = 'failure'
    AND action_category IN ('authentication', 'password')
    AND created_at > NOW() - INTERVAL '15 minutes';

  -- Check for requests from multiple IPs in last 5 minutes
  SELECT COUNT(DISTINCT ip_address)
  INTO v_different_ips
  FROM admin_audit_logs
  WHERE user_email = NEW.user_email
    AND created_at > NOW() - INTERVAL '5 minutes'
    AND ip_address IS NOT NULL;

  -- Flag as suspicious if conditions met
  IF v_recent_failures >= 3 THEN
    NEW.is_suspicious := true;
    NEW.severity := 'high';
  ELSIF v_different_ips >= 3 THEN
    NEW.is_suspicious := true;
    NEW.severity := 'medium';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: discover_zone_candidates(numeric, text, numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.discover_zone_candidates(p_min_fit_score numeric DEFAULT 40, p_province text DEFAULT NULL::text, p_max_existing_zone_distance_km numeric DEFAULT 3.0, p_limit integer DEFAULT 50) RETURNS TABLE(ward_code text, ward_name text, municipality text, province text, centroid_lat double precision, centroid_lng double precision, demographic_fit_score numeric, pct_no_internet numeric, pct_income_above_r12800 numeric, pct_employed numeric, total_population integer, total_households integer, business_poi_count integer, office_poi_count integer, healthcare_poi_count integer, nearby_base_stations bigint, nearby_base_connections bigint, nearby_dfa_connected bigint, nearby_dfa_near_net bigint)
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    wd.ward_code,
    wd.ward_name,
    wd.municipality,
    wd.province,
    wd.centroid_lat,
    wd.centroid_lng,
    wd.demographic_fit_score,
    wd.pct_no_internet,
    wd.pct_income_above_r12800,
    wd.pct_employed,
    wd.total_population,
    wd.total_households,
    wd.business_poi_count,
    wd.office_poi_count,
    wd.healthcare_poi_count,
    COALESCE((
      SELECT COUNT(*)
      FROM tarana_base_stations tbs
      WHERE ST_DWithin(
        ST_SetSRID(ST_MakePoint(tbs.lng, tbs.lat), 4326)::GEOGRAPHY,
        ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY,
        5000
      )
    ), 0)::BIGINT,
    COALESCE((
      SELECT SUM(tbs.active_connections)
      FROM tarana_base_stations tbs
      WHERE ST_DWithin(
        ST_SetSRID(ST_MakePoint(tbs.lng, tbs.lat), 4326)::GEOGRAPHY,
        ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY,
        5000
      )
    ), 0)::BIGINT,
    COALESCE((
      SELECT COUNT(*)
      FROM dfa_buildings db
      WHERE db.coverage_type = 'connected'
        AND ST_DWithin(
          ST_SetSRID(ST_MakePoint(db.longitude, db.latitude), 4326)::GEOGRAPHY,
          ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY,
          3000
        )
    ), 0)::BIGINT,
    COALESCE((
      SELECT COUNT(*)
      FROM dfa_buildings db
      WHERE db.coverage_type = 'near-net'
        AND ST_DWithin(
          ST_SetSRID(ST_MakePoint(db.longitude, db.latitude), 4326)::GEOGRAPHY,
          ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY,
          3000
        )
    ), 0)::BIGINT
  FROM ward_demographics wd
  WHERE wd.demographic_fit_score >= p_min_fit_score
    AND (p_province IS NULL OR wd.province = p_province)
    AND wd.centroid_lat IS NOT NULL
    AND wd.centroid_lng IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM sales_zones sz
      WHERE sz.status = 'active'
      AND ST_DWithin(
        ST_SetSRID(ST_MakePoint(sz.center_lng, sz.center_lat), 4326)::GEOGRAPHY,
        ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY,
        p_max_existing_zone_distance_km * 1000
      )
    )
    AND NOT EXISTS (
      SELECT 1 FROM zone_discovery_candidates zdc
      WHERE zdc.ward_code = wd.ward_code
      AND zdc.status = 'pending'
    )
  ORDER BY wd.demographic_fit_score DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: enforce_invoice_immutability(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_invoice_immutability() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
  BEGIN
      -- Allow status changes and specific field updates even when locked
      IF OLD.is_locked = true THEN
          -- Only allow these fields to be updated on locked invoices
          IF (
              NEW.status IS DISTINCT FROM OLD.status OR
              NEW.amount_paid IS DISTINCT FROM OLD.amount_paid OR
              NEW.amount_due IS DISTINCT FROM OLD.amount_due OR
              NEW.paid_at IS DISTINCT FROM OLD.paid_at OR
              NEW.emailed_at IS DISTINCT FROM OLD.emailed_at OR
              NEW.email_attempts IS DISTINCT FROM OLD.email_attempts OR
              NEW.voided_at IS DISTINCT FROM OLD.voided_at OR
              NEW.voided_by IS DISTINCT FROM OLD.voided_by OR
              NEW.void_reason IS DISTINCT FROM OLD.void_reason OR
              NEW.updated_at IS DISTINCT FROM OLD.updated_at OR
              NEW.zoho_invoice_id IS DISTINCT FROM OLD.zoho_invoice_id OR
              NEW.zoho_pdf_url IS DISTINCT FROM OLD.zoho_pdf_url OR
              NEW.zoho_sync_status IS DISTINCT FROM OLD.zoho_sync_status OR
              NEW.zoho_last_synced_at IS DISTINCT FROM OLD.zoho_last_synced_at OR
              NEW.zoho_last_sync_error IS DISTINCT FROM OLD.zoho_last_sync_error OR
              NEW.reminder_sent_at IS DISTINCT FROM OLD.reminder_sent_at OR
              NEW.reminder_count IS DISTINCT FROM OLD.reminder_count OR
              NEW.reminder_error IS DISTINCT FROM OLD.reminder_error OR
              NEW.notes IS DISTINCT FROM OLD.notes
          ) THEN
              -- These changes are allowed
              RETURN NEW;
          END IF;

          -- Block changes to financial data
          IF (
              NEW.subtotal IS DISTINCT FROM OLD.subtotal OR
              NEW.tax_amount IS DISTINCT FROM OLD.tax_amount OR
              NEW.total_amount IS DISTINCT FROM OLD.total_amount OR
              NEW.line_items IS DISTINCT FROM OLD.line_items OR
              NEW.customer_id IS DISTINCT FROM OLD.customer_id OR
              NEW.invoice_number IS DISTINCT FROM OLD.invoice_number OR
              NEW.invoice_date IS DISTINCT FROM OLD.invoice_date OR
              NEW.due_date IS DISTINCT FROM OLD.due_date
          ) THEN
              RAISE EXCEPTION 'Cannot modify locked invoice. Use credit note for corrections.';        
          END IF;
      END IF;

      -- Auto-lock invoice when status changes to 'sent'
      IF NEW.status = 'sent' AND OLD.status = 'draft' THEN
          NEW.is_locked := true;
          NEW.locked_at := NOW();
          NEW.locked_reason := 'Invoice sent to customer';
      END IF;

      RETURN NEW;
  END;
  $$;


--
-- Name: find_customer_service_by_interstellio_id(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_customer_service_by_interstellio_id(p_interstellio_id character varying) RETURNS TABLE(customer_service_id uuid, customer_id uuid, customer_name character varying, customer_email character varying, package_name character varying, service_status character varying)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        cs.id AS customer_service_id,
        cs.customer_id,
        CONCAT(c.first_name, ' ', c.last_name)::VARCHAR AS customer_name,
        c.email::VARCHAR AS customer_email,
        cs.package_name::VARCHAR,
        cs.status::VARCHAR AS service_status
    FROM public.customer_services cs
    JOIN public.customers c ON cs.customer_id = c.id
    WHERE cs.connection_id = p_interstellio_id
    LIMIT 1;
END;
$$;


--
-- Name: find_nearest_dfa_building(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_nearest_dfa_building(p_lat double precision, p_lng double precision, p_limit integer DEFAULT 3) RETURNS TABLE(id uuid, building_name text, building_id text, street_address text, coverage_type text, ftth text, precinct text, latitude double precision, longitude double precision, distance_km numeric)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT d.id, d.building_name, d.building_id, d.street_address,
    d.coverage_type, d.ftth, d.precinct, d.latitude, d.longitude,
    ROUND((ST_Distance(
      ST_SetSRID(ST_MakePoint(d.longitude, d.latitude), 4326)::geography,
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
    ) / 1000)::numeric, 2) AS distance_km
  FROM dfa_buildings d
  ORDER BY ST_SetSRID(ST_MakePoint(d.longitude, d.latitude), 4326)::geography <->
           ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
  LIMIT p_limit;
$$;


--
-- Name: find_nearest_tarana_base_station(numeric, numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.find_nearest_tarana_base_station(p_lat numeric, p_lng numeric, p_limit integer DEFAULT 5) RETURNS TABLE(id uuid, serial_number text, hostname text, site_name text, active_connections integer, market text, lat numeric, lng numeric, distance_km numeric)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT
    t.id,
    t.serial_number,
    t.hostname,
    t.site_name,
    t.active_connections,
    t.market,
    t.lat,
    t.lng,
    ROUND(
      (ST_Distance(
        ST_SetSRID(ST_MakePoint(t.lng, t.lat), 4326)::geography,
        ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
      ) / 1000)::numeric,
      2
    ) as distance_km
  FROM tarana_base_stations t
  ORDER BY ST_SetSRID(ST_MakePoint(t.lng, t.lat), 4326)::geography <->
           ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
  LIMIT p_limit;
$$;


--
-- Name: FUNCTION find_nearest_tarana_base_station(p_lat numeric, p_lng numeric, p_limit integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.find_nearest_tarana_base_station(p_lat numeric, p_lng numeric, p_limit integer) IS 'Find nearest Tarana base stations to a given lat/lng with distance in km.';


