--
-- Name: generate_account_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_account_number() RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    current_year INTEGER;
    next_number INTEGER;
    account_num TEXT;
BEGIN
    -- Get current year
    current_year := EXTRACT(YEAR FROM NOW());
    
    -- Atomically increment counter for current year
    -- If year doesn't exist, initialize with counter = 1
    INSERT INTO public.account_number_counter (year, counter)
    VALUES (current_year, 1)
    ON CONFLICT (year) 
    DO UPDATE SET 
        counter = account_number_counter.counter + 1,
        updated_at = NOW()
    RETURNING counter INTO next_number;
    
    -- Format: CT-YYYY-NNNNN (e.g., CT-2025-00001)
    account_num := 'CT-' || current_year || '-' || LPAD(next_number::TEXT, 5, '0');
    
    RETURN account_num;
END;
$$;


--
-- Name: FUNCTION generate_account_number(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.generate_account_number() IS 'Generates unique account number with format CT-YYYY-NNNNN using atomic counter increment';


--
-- Name: generate_ambassador_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_ambassador_number() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  year_suffix TEXT;
  sequence_num INTEGER;
  new_number TEXT;
BEGIN
  IF NEW.status = 'approved' AND OLD.status != 'approved' AND NEW.ambassador_number IS NULL THEN
    year_suffix := TO_CHAR(NOW(), 'YYYY');

    -- Get next sequence number for this year
    SELECT COALESCE(MAX(
      CAST(SUBSTRING(ambassador_number FROM 'CTAB-' || year_suffix || '-(\d+)') AS INTEGER)
    ), 0) + 1
    INTO sequence_num
    FROM ambassadors
    WHERE ambassador_number LIKE 'CTAB-' || year_suffix || '-%';

    new_number := 'CTAB-' || year_suffix || '-' || LPAD(sequence_num::TEXT, 3, '0');
    NEW.ambassador_number := new_number;
    NEW.approved_at := NOW();
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: generate_business_account_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_business_account_number() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  current_year TEXT;
  next_number INTEGER;
  new_account_number TEXT;
BEGIN
  current_year := TO_CHAR(NOW(), 'YYYY');
  SELECT COALESCE(MAX(
    CAST(SUBSTRING(account_number FROM 'CT-B-' || current_year || '-(\d+)') AS INTEGER)
  ), 0) + 1
  INTO next_number
  FROM business_customers
  WHERE account_number LIKE 'CT-B-' || current_year || '-%';
  new_account_number := 'CT-B-' || current_year || '-' || LPAD(next_number::TEXT, 5, '0');
  NEW.account_number := new_account_number;
  RETURN NEW;
END;
$$;


--
-- Name: generate_contract_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_contract_number() RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  current_year TEXT;
  next_sequence INTEGER;
BEGIN
  current_year := TO_CHAR(NOW(), 'YYYY');
  SELECT COUNT(*) + 1 INTO next_sequence
  FROM contracts
  WHERE contract_number LIKE 'CT-' || current_year || '-%';
  RETURN 'CT-' || current_year || '-' || LPAD(next_sequence::TEXT, 3, '0');
END;
$$;


--
-- Name: generate_corporate_site_account_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_corporate_site_account_number() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  corp_code VARCHAR(10);
  next_num INTEGER;
BEGIN
  -- Get corporate code from parent
  SELECT corporate_code INTO corp_code
  FROM corporate_accounts
  WHERE id = NEW.corporate_id;

  IF corp_code IS NULL THEN
    RAISE EXCEPTION 'Corporate account not found for id: %', NEW.corporate_id;
  END IF;

  -- Get next site number for this corporate
  SELECT COALESCE(MAX(site_number), 0) + 1 INTO next_num
  FROM corporate_sites
  WHERE corporate_id = NEW.corporate_id;

  -- Set values
  NEW.site_number := next_num;
  NEW.account_number := 'CT-' || corp_code || '-' || LPAD(next_num::TEXT, 3, '0');

  -- Auto-generate PPPoE username
  NEW.pppoe_username := NEW.account_number || '@circletel.co.za';

  RETURN NEW;
END;
$$;


--
-- Name: generate_credit_note_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_credit_note_number() RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    current_year INTEGER;
    next_number INTEGER;
    cn_num TEXT;
BEGIN
    current_year := EXTRACT(YEAR FROM NOW());
    next_number := nextval('public.credit_note_number_seq');
