--
-- Name: generate_incident_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_incident_number() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  year_part TEXT;
  seq_num INTEGER;
BEGIN
  year_part := TO_CHAR(NOW(), 'YYYY');
  SELECT COALESCE(MAX(CAST(SUBSTRING(incident_number FROM 'INC-\d{4}-(\d+)') AS INTEGER)), 0) + 1
  INTO seq_num
  FROM outage_incidents
  WHERE incident_number LIKE 'INC-' || year_part || '-%';
  NEW.incident_number := 'INC-' || year_part || '-' || LPAD(seq_num::TEXT, 4, '0');
  RETURN NEW;
END;
$$;


--
-- Name: generate_invoice_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_invoice_number() RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  current_year TEXT;
