--
-- Name: generate_job_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_job_number() RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
    today_date TEXT;
    seq_num INTEGER;
    new_job_number TEXT;
BEGIN
    today_date := TO_CHAR(NOW(), 'YYYYMMDD');
    
    SELECT COALESCE(MAX(
        CAST(SUBSTRING(job_number FROM 'JOB-' || today_date || '-(\d+)') AS INTEGER)
    ), 0) + 1
    INTO seq_num
    FROM field_jobs
    WHERE job_number LIKE 'JOB-' || today_date || '-%';
    
    new_job_number := 'JOB-' || today_date || '-' || LPAD(seq_num::TEXT, 3, '0');
    
    RETURN new_job_number;
END;
$$;


--
-- Name: generate_order_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_order_number() RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  order_num TEXT;
  exists_check INTEGER;
BEGIN
  LOOP
    order_num := 'ORD-' || TO_CHAR(NOW(), 'YYYYMMDD') || '-' || LPAD(FLOOR(RANDOM() * 10000)::TEXT, 4, '0');
    SELECT COUNT(*) INTO exists_check FROM consumer_orders WHERE order_number = order_num;
    EXIT WHEN exists_check = 0;
  END LOOP;
  RETURN order_num;
END;
$$;


--
-- Name: generate_quote_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_quote_number() RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  year_part TEXT;
  next_num INTEGER;
  quote_num TEXT;
BEGIN
  year_part := TO_CHAR(CURRENT_DATE, 'YYYY');

  -- Get next sequence number for this year
  SELECT COALESCE(MAX(CAST(SUBSTRING(quote_number FROM 9) AS INTEGER)), 0) + 1
  INTO next_num
  FROM business_quotes
  WHERE quote_number LIKE 'BQ-' || year_part || '-%';

  -- Format as BQ-YYYY-NNN (zero-padded to 3 digits)
  quote_num := 'BQ-' || year_part || '-' || LPAD(next_num::TEXT, 3, '0');

  RETURN quote_num;
END;
$$;


--
-- Name: generate_quote_share_token(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_quote_share_token(quote_uuid uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  token TEXT;
  token_exists BOOLEAN;
BEGIN
  LOOP
    -- Generate a random 32-character token
    token := encode(gen_random_bytes(24), 'base64');
    -- Remove special characters and make URL-safe
    token := replace(replace(replace(token, '/', ''), '+', ''), '=', '');

    -- Check if token already exists
    SELECT EXISTS(
      SELECT 1 FROM public.business_quotes WHERE share_token = token
    ) INTO token_exists;

    -- Exit loop if token is unique
    EXIT WHEN NOT token_exists;
  END LOOP;

  -- Update the quote with the new token
  UPDATE public.business_quotes
  SET share_token = token,
      share_enabled = true,
      updated_at = NOW()
  WHERE id = quote_uuid;

  RETURN token;
END;
$$;


--
-- Name: get_ai_usage_by_type(uuid, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ai_usage_by_type(target_user_id uuid DEFAULT auth.uid(), start_date timestamp with time zone DEFAULT date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone), end_date timestamp with time zone DEFAULT now()) RETURNS TABLE(request_type text, request_count bigint, total_tokens bigint, total_cost_cents bigint, success_rate numeric)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT
    request_type,
    COUNT(*)::BIGINT as request_count,
    COALESCE(SUM(input_tokens + output_tokens), 0)::BIGINT as total_tokens,
    COALESCE(SUM(estimated_cost_cents), 0)::BIGINT as total_cost_cents,
    ROUND(
      (COUNT(*) FILTER (WHERE success = true)::NUMERIC / COUNT(*)::NUMERIC) * 100,
      2
    ) as success_rate
  FROM public.ai_usage_logs
  WHERE user_id = target_user_id
    AND created_at BETWEEN start_date AND end_date
  GROUP BY request_type
  ORDER BY request_count DESC;
$$;


--
-- Name: get_allowed_next_statuses(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_allowed_next_statuses(current_status text) RETURNS text[]
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN CASE current_status
    WHEN 'pending' THEN ARRAY['payment_method_pending', 'cancelled']::TEXT[]
    WHEN 'payment_method_pending' THEN ARRAY['payment_method_registered', 'cancelled']::TEXT[]
    WHEN 'payment_method_registered' THEN ARRAY['installation_scheduled', 'cancelled']::TEXT[]
    WHEN 'installation_scheduled' THEN ARRAY['installation_in_progress', 'cancelled']::TEXT[]
    WHEN 'installation_in_progress' THEN ARRAY['installation_completed', 'failed', 'cancelled']::TEXT[]
    WHEN 'installation_completed' THEN ARRAY['active', 'failed', 'cancelled']::TEXT[]
    WHEN 'active' THEN ARRAY['suspended', 'cancelled']::TEXT[]
    WHEN 'suspended' THEN ARRAY['active', 'cancelled']::TEXT[]
    WHEN 'failed' THEN ARRAY['installation_scheduled', 'cancelled']::TEXT[]
    WHEN 'cancelled' THEN ARRAY[]::TEXT[] -- No transitions from cancelled
    ELSE ARRAY['cancelled']::TEXT[] -- Default: can always cancel
  END;
END;
$$;


--
-- Name: FUNCTION get_allowed_next_statuses(current_status text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_allowed_next_statuses(current_status text) IS 'Returns array of valid next status values based on current status. Used for workflow validation.';


--
-- Name: get_billing_setting(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_billing_setting(p_key text, p_customer_type text DEFAULT 'global'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_value JSONB;
BEGIN
  SELECT setting_value INTO v_value
  FROM billing_settings
  WHERE setting_key = p_key
    AND customer_type = p_customer_type;

  IF v_value IS NULL AND p_customer_type != 'global' THEN
    SELECT setting_value INTO v_value
    FROM billing_settings
    WHERE setting_key = p_key
      AND customer_type = 'global';
  END IF;

  RETURN v_value;
END;
$$;


--
-- Name: FUNCTION get_billing_setting(p_key text, p_customer_type text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_billing_setting(p_key text, p_customer_type text) IS 'Retrieves a billing setting value, with fallback to global.';


--
-- Name: get_billing_setting_bool(text, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_billing_setting_bool(p_key text, p_customer_type text DEFAULT 'global'::text, p_default boolean DEFAULT false) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_value JSONB;
  v_text TEXT;
BEGIN
  v_value := get_billing_setting(p_key, p_customer_type);
  IF v_value IS NULL THEN
    RETURN p_default;
  END IF;
  v_text := v_value #>> '{}';
  RETURN COALESCE(v_text = 'true' OR v_text = '1', p_default);
EXCEPTION WHEN OTHERS THEN
  RETURN p_default;
END;
$$;


