CREATE FUNCTION public.get_billing_setting_numeric(p_key text, p_customer_type text DEFAULT 'global'::text, p_default numeric DEFAULT 0) RETURNS numeric
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
