-- Name: get_cms_media_path(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cms_media_path(file_extension text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  user_id_str text;
  date_path text;
begin
  -- Get current user ID
  user_id_str := auth.uid()::text;

  -- Create date-based folder structure: YYYY/MM/
  date_path := to_char(now(), 'YYYY/MM');

  -- Return path: user_id/YYYY/MM/filename.ext
  return user_id_str || '/' || date_path || '/' || gen_random_uuid()::text || file_extension;
end;
$$;


