--

COMMENT ON FUNCTION public.get_cms_media_path(file_extension text) IS 'Generates organized storage path for CMS media uploads: user_id/YYYY/MM/uuid.ext';


--
-- Name: get_coverage_time_series(timestamp with time zone, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_coverage_time_series(p_start_time timestamp with time zone, p_end_time timestamp with time zone, p_interval text DEFAULT '1 hour'::text) RETURNS TABLE(time_bucket timestamp with time zone, total_requests bigint, successful_requests bigint, failed_requests bigint, success_rate numeric, avg_response_time numeric, min_response_time integer, max_response_time integer, error_count bigint)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    date_trunc('hour', created_at) + 
      (EXTRACT(hour FROM created_at)::INTEGER / 
        CASE 
          WHEN p_interval = '4 hours' THEN 4
          WHEN p_interval = '1 day' THEN 24
          ELSE 1
        END * 
        CASE 
          WHEN p_interval = '4 hours' THEN 4
          WHEN p_interval = '1 day' THEN 24
          ELSE 1
        END
      ) * INTERVAL '1 hour' AS time_bucket,
    COUNT(*)::BIGINT AS total_requests,
    COUNT(*) FILTER (WHERE success = true)::BIGINT AS successful_requests,
    COUNT(*) FILTER (WHERE success = false)::BIGINT AS failed_requests,
    CASE 
      WHEN COUNT(*) > 0 THEN 
        (COUNT(*) FILTER (WHERE success = true)::NUMERIC / COUNT(*) * 100)
      ELSE 0 
    END AS success_rate,
    AVG(response_time_ms)::NUMERIC AS avg_response_time,
    MIN(response_time_ms) AS min_response_time,
    MAX(response_time_ms) AS max_response_time,
    COUNT(*) FILTER (WHERE error_code IS NOT NULL)::BIGINT AS error_count
  FROM coverage_check_logs
  WHERE created_at >= p_start_time
    AND created_at <= p_end_time
  GROUP BY time_bucket
  ORDER BY time_bucket ASC;
END;
$$;


--
-- Name: FUNCTION get_coverage_time_series(p_start_time timestamp with time zone, p_end_time timestamp with time zone, p_interval text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_coverage_time_series(p_start_time timestamp with time zone, p_end_time timestamp with time zone, p_interval text) IS 'Returns time-series data for coverage check requests';


