--
-- Name: get_current_price_for_customer(uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_price_for_customer(p_service_package_id uuid, p_customer_signup_date timestamp with time zone DEFAULT now()) RETURNS numeric
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_current_price DECIMAL(10,2);
  v_published_change RECORD;
BEGIN
  -- Get current package price
  SELECT price INTO v_current_price
  FROM service_packages
  WHERE id = p_service_package_id;

  -- Check for published price change
  SELECT * INTO v_published_change
  FROM price_changes
  WHERE service_package_id = p_service_package_id
    AND status = 'published'
  LIMIT 1;

  -- No published price change - return current price
  IF v_published_change IS NULL THEN
    RETURN v_current_price;
  END IF;

  -- Customer signed up AFTER price change published?
  IF p_customer_signup_date >= v_published_change.published_at THEN
    -- New customer gets new price immediately
    RETURN v_published_change.new_price;
  ELSE
    -- Existing customer keeps old price until effective_date
    RETURN v_published_change.old_price;
  END IF;
END;
$$;


--
-- Name: FUNCTION get_current_price_for_customer(p_service_package_id uuid, p_customer_signup_date timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_current_price_for_customer(p_service_package_id uuid, p_customer_signup_date timestamp with time zone) IS 'Returns applicable price for customer based on signup date. New customers (after published_at) get new price immediately, existing customers keep old price until effective_date.';


--
-- Name: get_demographics_in_radius(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_demographics_in_radius(p_lat double precision, p_lng double precision, p_radius_km double precision DEFAULT 3.0) RETURNS TABLE(ward_count integer, total_population bigint, total_households bigint, avg_pct_no_internet numeric, avg_pct_cellphone_internet numeric, avg_pct_fixed_internet numeric, avg_pct_income_above_r12800 numeric, avg_pct_income_r6400_12800 numeric, avg_pct_employed numeric, avg_pct_formal_dwelling numeric, total_business_pois bigint, total_office_pois bigint, total_healthcare_pois bigint, avg_demographic_fit_score numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE search_point GEOGRAPHY;
BEGIN
  search_point := ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::GEOGRAPHY;
  RETURN QUERY SELECT
    COUNT(*)::INTEGER, COALESCE(SUM(wd.total_population), 0)::BIGINT,
    COALESCE(SUM(wd.total_households), 0)::BIGINT,
    COALESCE(AVG(wd.pct_no_internet), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_cellphone_internet), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_fixed_internet), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_income_above_r12800), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_income_r6400_12800), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_employed), 0)::DECIMAL(5,2),
    COALESCE(AVG(wd.pct_formal_dwelling), 0)::DECIMAL(5,2),
    COALESCE(SUM(wd.business_poi_count), 0)::BIGINT,
    COALESCE(SUM(wd.office_poi_count), 0)::BIGINT,
    COALESCE(SUM(wd.healthcare_poi_count), 0)::BIGINT,
    COALESCE(AVG(wd.demographic_fit_score), 0)::DECIMAL(5,2)
  FROM ward_demographics wd
  WHERE wd.boundary IS NOT NULL AND ST_DWithin(wd.boundary, search_point, p_radius_km * 1000);
END; $$;


--
-- Name: get_error_distribution(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_error_distribution(p_start_time timestamp with time zone, p_end_time timestamp with time zone) RETURNS TABLE(error_type character varying, error_count bigint, percentage numeric, sample_message text)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_total_errors BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_total_errors
  FROM coverage_check_logs
  WHERE created_at >= p_start_time
    AND created_at <= p_end_time
    AND error_type IS NOT NULL;

  RETURN QUERY
  SELECT
    ccl.error_type,
    COUNT(*)::BIGINT AS error_count,
    CASE 
      WHEN v_total_errors > 0 THEN 
        (COUNT(*)::NUMERIC / v_total_errors * 100)
      ELSE 0 
    END AS percentage,
    (ARRAY_AGG(ccl.error_message ORDER BY ccl.created_at DESC))[1] AS sample_message
  FROM coverage_check_logs ccl
  WHERE ccl.created_at >= p_start_time
    AND ccl.created_at <= p_end_time
    AND ccl.error_type IS NOT NULL
  GROUP BY ccl.error_type
  ORDER BY error_count DESC;
END;
$$;


--
-- Name: FUNCTION get_error_distribution(p_start_time timestamp with time zone, p_end_time timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_error_distribution(p_start_time timestamp with time zone, p_end_time timestamp with time zone) IS 'Returns error distribution with percentages';


