--
-- Name: get_provider_performance(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_provider_performance(p_start_time timestamp with time zone, p_end_time timestamp with time zone) RETURNS TABLE(provider_code character varying, provider_name character varying, total_requests bigint, success_rate numeric, avg_response_time numeric, p95_response_time numeric, coverage_rate numeric)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ccl.provider_code,
    ccl.provider_name,
    COUNT(*)::BIGINT AS total_requests,
    CASE 
      WHEN COUNT(*) > 0 THEN 
        (COUNT(*) FILTER (WHERE ccl.success = true)::NUMERIC / COUNT(*) * 100)
      ELSE 0 
    END AS success_rate,
    AVG(ccl.response_time_ms)::NUMERIC AS avg_response_time,
    PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY ccl.response_time_ms)::NUMERIC AS p95_response_time,
    CASE 
      WHEN COUNT(*) > 0 THEN 
        (COUNT(*) FILTER (WHERE ccl.has_coverage = true)::NUMERIC / COUNT(*) * 100)
      ELSE 0 
    END AS coverage_rate
  FROM coverage_check_logs ccl
  WHERE ccl.created_at >= p_start_time
    AND ccl.created_at <= p_end_time
    AND ccl.provider_code IS NOT NULL
  GROUP BY ccl.provider_code, ccl.provider_name
  ORDER BY total_requests DESC;
END;
$$;


--
-- Name: FUNCTION get_provider_performance(p_start_time timestamp with time zone, p_end_time timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_provider_performance(p_start_time timestamp with time zone, p_end_time timestamp with time zone) IS 'Returns performance metrics by provider';


--
-- Name: get_province_statistics(timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_province_statistics(p_start_time timestamp with time zone, p_end_time timestamp with time zone) RETURNS TABLE(province character varying, total_requests bigint, successful_requests bigint, success_rate numeric, avg_response_time numeric, coverage_found bigint)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ccl.province,
    COUNT(*)::BIGINT AS total_requests,
    COUNT(*) FILTER (WHERE ccl.success = true)::BIGINT AS successful_requests,
    CASE 
      WHEN COUNT(*) > 0 THEN 
        (COUNT(*) FILTER (WHERE ccl.success = true)::NUMERIC / COUNT(*) * 100)
      ELSE 0 
    END AS success_rate,
    AVG(ccl.response_time_ms)::NUMERIC AS avg_response_time,
    COUNT(*) FILTER (WHERE ccl.has_coverage = true)::BIGINT AS coverage_found
  FROM coverage_check_logs ccl
  WHERE ccl.created_at >= p_start_time
    AND ccl.created_at <= p_end_time
    AND ccl.province IS NOT NULL
  GROUP BY ccl.province
  ORDER BY total_requests DESC;
END;
$$;


--
-- Name: FUNCTION get_province_statistics(p_start_time timestamp with time zone, p_end_time timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_province_statistics(p_start_time timestamp with time zone, p_end_time timestamp with time zone) IS 'Returns statistics grouped by province';


--
-- Name: get_sync_candidates(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_sync_candidates(max_limit integer DEFAULT 100) RETURNS TABLE(id uuid, sku text, name character varying, status text, last_synced_at timestamp with time zone, sync_status text, zoho_crm_product_id text, zoho_billing_plan_id text, zoho_billing_item_id text, zoho_crm_sync_status text, zoho_billing_sync_status text, zoho_crm_last_synced_at timestamp with time zone, zoho_billing_last_synced_at timestamp with time zone)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH ranked_candidates AS (
    SELECT
      sp.id,
      sp.sku,
      sp.name,
      sp.status,
      pi.last_synced_at,
      pi.sync_status,
      pi.zoho_crm_product_id,
      pi.zoho_billing_plan_id,
      pi.zoho_billing_item_id,
      pi.zoho_crm_sync_status,
      pi.zoho_billing_sync_status,
      pi.zoho_crm_last_synced_at,
      pi.zoho_billing_last_synced_at,
      -- Priority scoring (lower = higher priority)
      CASE
        -- Failed syncs (CRM or Billing)
        WHEN pi.zoho_crm_sync_status = 'failed' OR pi.zoho_billing_sync_status = 'failed' THEN 1
        -- Never synced (no integration record)
        WHEN pi.id IS NULL THEN 2
        -- Stale CRM sync (> 24 hours)
        WHEN pi.zoho_crm_last_synced_at IS NOT NULL
          AND pi.zoho_crm_last_synced_at < NOW() - INTERVAL '24 hours' THEN 3
        -- Stale Billing sync (> 24 hours)
        WHEN pi.zoho_billing_last_synced_at IS NOT NULL
          AND pi.zoho_billing_last_synced_at < NOW() - INTERVAL '24 hours' THEN 3
        -- Legacy: Check old last_synced_at if new columns are NULL
        WHEN pi.last_synced_at IS NOT NULL
          AND pi.last_synced_at < NOW() - INTERVAL '24 hours' THEN 3
        ELSE 999 -- Not a candidate
      END AS priority
    FROM service_packages sp
    LEFT JOIN product_integrations pi ON pi.service_package_id = sp.id
    WHERE sp.status = 'active'
  )
  SELECT
    rc.id,
    rc.sku,
    rc.name,
    rc.status,
    rc.last_synced_at,
    rc.sync_status,
    rc.zoho_crm_product_id,
    rc.zoho_billing_plan_id,
    rc.zoho_billing_item_id,
    rc.zoho_crm_sync_status,
    rc.zoho_billing_sync_status,
    rc.zoho_crm_last_synced_at,
    rc.zoho_billing_last_synced_at
  FROM ranked_candidates rc
  WHERE rc.priority < 999
  ORDER BY rc.priority ASC, rc.id ASC
  LIMIT max_limit;
END;
$$;


