--
-- Name: get_user_daily_ai_usage(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_daily_ai_usage(target_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(request_count bigint, total_tokens bigint, total_cost_cents bigint, last_request timestamp with time zone)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT
    COUNT(*)::BIGINT as request_count,
    COALESCE(SUM(input_tokens + output_tokens), 0)::BIGINT as total_tokens,
    COALESCE(SUM(estimated_cost_cents), 0)::BIGINT as total_cost_cents,
    MAX(created_at) as last_request
  FROM public.ai_usage_logs
  WHERE user_id = target_user_id
    AND created_at >= CURRENT_DATE
    AND success = true;
$$;


--
-- Name: get_user_monthly_ai_usage(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_monthly_ai_usage(target_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(request_count bigint, total_tokens bigint, total_cost_cents bigint, avg_response_time_ms numeric)
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT
    COUNT(*)::BIGINT as request_count,
    COALESCE(SUM(input_tokens + output_tokens), 0)::BIGINT as total_tokens,
    COALESCE(SUM(estimated_cost_cents), 0)::BIGINT as total_cost_cents,
    COALESCE(AVG(response_time_ms), 0)::NUMERIC as avg_response_time_ms
  FROM public.ai_usage_logs
  WHERE user_id = target_user_id
    AND created_at >= DATE_TRUNC('month', CURRENT_DATE)
    AND success = true;
$$;


--
-- Name: get_user_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_permissions(user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_permissions JSONB;
  v_template_permissions JSONB;
  v_custom_permissions JSONB;
BEGIN
  -- Get permissions from role template
  SELECT COALESCE(rt.permissions, '[]'::jsonb)
  INTO v_template_permissions
  FROM admin_users au
  LEFT JOIN role_templates rt ON rt.id = au.role_template_id
  WHERE au.id = user_id;

  -- Get custom permissions
  SELECT COALESCE(custom_permissions, '[]'::jsonb)
  INTO v_custom_permissions
  FROM admin_users
  WHERE id = user_id;

  -- Merge permissions (custom permissions override template)
  v_permissions := v_template_permissions || v_custom_permissions;
  
  RETURN v_permissions;
END;
$$;


--
-- Name: get_whatsapp_eligible_customers(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_whatsapp_eligible_customers(p_invoice_ids uuid[]) RETURNS TABLE(invoice_id uuid, invoice_number text, customer_id uuid, customer_name text, phone text, total_amount numeric, due_date date)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ci.id AS invoice_id,
    ci.invoice_number,
    c.id AS customer_id,
    CONCAT(c.first_name, ' ', c.last_name) AS customer_name,
    c.phone,
    ci.total_amount,
    ci.due_date
  FROM customer_invoices ci
  JOIN customers c ON c.id = ci.customer_id
  WHERE ci.id = ANY(p_invoice_ids)
    AND c.whatsapp_consent = true
    AND c.phone IS NOT NULL
    AND c.phone != ''
    AND ci.whatsapp_sent_at IS NULL; -- Not already sent
END;
$$;


