--
-- Name: has_required_compliance_documents(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.has_required_compliance_documents(p_order_id uuid) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_has_fica_id BOOLEAN;
  v_has_fica_address BOOLEAN;
  v_has_rica_id BOOLEAN;
  v_has_rica_residence BOOLEAN;
BEGIN
  -- Check FICA identity document
  SELECT EXISTS (
    SELECT 1 FROM compliance_documents
    WHERE order_id = p_order_id
    AND category = 'fica'
    AND document_type IN ('id_document', 'passport', 'drivers_license')
    AND status = 'approved'
  ) INTO v_has_fica_id;

  -- Check FICA address document
  SELECT EXISTS (
    SELECT 1 FROM compliance_documents
    WHERE order_id = p_order_id
    AND category = 'fica'
    AND document_type = 'proof_of_address'
    AND status = 'approved'
  ) INTO v_has_fica_address;

  -- Check RICA identity document
  SELECT EXISTS (
    SELECT 1 FROM compliance_documents
    WHERE order_id = p_order_id
    AND category = 'rica'
    AND document_type IN ('id_document', 'passport', 'asylum_document')
    AND status = 'approved'
  ) INTO v_has_rica_id;

  -- Check RICA residence document
  SELECT EXISTS (
    SELECT 1 FROM compliance_documents
    WHERE order_id = p_order_id
    AND category = 'rica'
    AND document_type = 'proof_of_residence'
    AND status = 'approved'
  ) INTO v_has_rica_residence;

  RETURN v_has_fica_id AND v_has_fica_address AND v_has_rica_id AND v_has_rica_residence;
END;
$$;


--
-- Name: FUNCTION has_required_compliance_documents(p_order_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.has_required_compliance_documents(p_order_id uuid) IS 'Check if order has all required approved documents';


