--
-- Name: initialize_business_journey(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.initialize_business_journey(p_business_customer_id uuid, p_quote_id uuid DEFAULT NULL::uuid) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  stages TEXT[] := ARRAY['quote_request', 'business_verification', 'site_details', 'contract', 'installation', 'go_live'];
  stage_docs JSONB[] := ARRAY[
    '[]'::JSONB,
    '["cipc_registration", "director_id", "proof_of_address"]'::JSONB,
    '["site_photos", "building_access_info"]'::JSONB,
    '[]'::JSONB,
    '[]'::JSONB,
    '[]'::JSONB
  ];
  i INTEGER;
BEGIN
  FOR i IN 1..6 LOOP
    INSERT INTO business_journey_stages (
      business_customer_id,
      quote_id,
      stage,
      step_number,
      status,
      required_documents
    ) VALUES (
      p_business_customer_id,
      p_quote_id,
      stages[i]::business_journey_stage,
      i,
      CASE WHEN i = 1 THEN 'in_progress' ELSE 'pending' END,
      stage_docs[i]
    )
    ON CONFLICT (business_customer_id, quote_id, stage) DO NOTHING;
  END LOOP;
END;
$$;


