--
-- Name: is_technician_available(uuid, date, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_technician_available(p_technician_id uuid, p_date date, p_time_slot text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public'
    AS $$
DECLARE
  v_day_name TEXT;
  v_working_hours JSONB;
  v_task_count INTEGER;
BEGIN
  -- Check if technician exists and is active
  SELECT is_active INTO STRICT v_working_hours
  FROM public.technicians
  WHERE id = p_technician_id;

  IF NOT FOUND OR v_working_hours = false THEN
    RETURN false;
  END IF;

  -- Get day of week
  v_day_name := LOWER(TO_CHAR(p_date, 'Day'));
  v_day_name := TRIM(v_day_name);

  -- Check working hours for that day
  SELECT working_hours -> v_day_name INTO v_working_hours
  FROM public.technicians
  WHERE id = p_technician_id;

  IF v_working_hours IS NULL OR v_working_hours = 'null'::JSONB THEN
    RETURN false; -- Not working on this day
  END IF;

  -- Check how many tasks already scheduled for that day/slot
  SELECT COUNT(*) INTO v_task_count
  FROM public.installation_tasks
  WHERE technician_id = p_technician_id
    AND scheduled_date = p_date
    AND status IN ('scheduled', 'in_progress')
    AND (p_time_slot IS NULL OR scheduled_time_slot = p_time_slot);

  -- Allow max 4 tasks per day (2 morning, 2 afternoon) or 2 per slot
  IF p_time_slot IS NOT NULL THEN
    RETURN v_task_count < 2;
  ELSE
    RETURN v_task_count < 4;
  END IF;
END;
$$;


--
-- Name: FUNCTION is_technician_available(p_technician_id uuid, p_date date, p_time_slot text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.is_technician_available(p_technician_id uuid, p_date date, p_time_slot text) IS 'Checks if technician is available on a specific date/time slot based on working hours and existing tasks.';


--
-- Name: log_admin_action(uuid, text, text, text, text, text, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_admin_action(p_user_id uuid, p_user_email text, p_action text, p_action_category text, p_ip_address text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb, p_status text DEFAULT 'success'::text, p_severity text DEFAULT 'low'::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_log_id UUID;
  v_admin_user_id UUID;
BEGIN
  -- Get admin_user_id if exists
  SELECT id INTO v_admin_user_id
  FROM admin_users
  WHERE email = p_user_email
  LIMIT 1;

  -- Insert audit log
  INSERT INTO admin_audit_logs (
    user_id,
    user_email,
    admin_user_id,
    action,
    action_category,
    ip_address,
    user_agent,
    metadata,
    status,
    severity
  ) VALUES (
    p_user_id,
    p_user_email,
    v_admin_user_id,
    p_action,
    p_action_category,
    p_ip_address,
    p_user_agent,
    p_metadata,
    p_status,
    p_severity
  )
  RETURNING id INTO v_log_id;

  RETURN v_log_id;
END;
$$;


