--
-- Name: log_job_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_job_status_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        INSERT INTO field_job_status_history (
            job_id,
            previous_status,
            new_status,
            changed_by
        ) VALUES (
            NEW.id,
            OLD.status,
            NEW.status,
            auth.uid()
        );
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: log_product_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_product_changes() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  changed_fields_array TEXT[];
BEGIN
  IF TG_OP = 'UPDATE' THEN
    -- Calculate which fields changed
    SELECT ARRAY(
      SELECT key FROM jsonb_each(to_jsonb(NEW))
      WHERE to_jsonb(NEW)->key IS DISTINCT FROM to_jsonb(OLD)->key
    ) INTO changed_fields_array;

    -- Only log if there are actual changes
    IF array_length(changed_fields_array, 1) > 0 THEN
      INSERT INTO product_audit_logs (
        product_id,
        action,
        old_values,
        new_values,
        changed_fields
      ) VALUES (
        OLD.id,
        'UPDATE',
        to_jsonb(OLD),
        to_jsonb(NEW),
        changed_fields_array
      );
    END IF;
  ELSIF TG_OP = 'INSERT' THEN
    INSERT INTO product_audit_logs (
      product_id,
      action,
      new_values
    ) VALUES (
      NEW.id,
      'INSERT',
      to_jsonb(NEW)
    );
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO product_audit_logs (
      product_id,
      action,
      old_values
    ) VALUES (
      OLD.id,
      'DELETE',
      to_jsonb(OLD)
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: log_service_package_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_service_package_changes() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO service_packages_audit_logs (package_id, action, new_values)
    VALUES (NEW.id, 'created', to_jsonb(NEW));
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    INSERT INTO service_packages_audit_logs (package_id, action, old_values, new_values)
    VALUES (NEW.id, 'updated', to_jsonb(OLD), to_jsonb(NEW));
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO service_packages_audit_logs (package_id, action, old_values)
    VALUES (OLD.id, 'deleted', to_jsonb(OLD));
    RETURN OLD;
  END IF;
END;
$$;


--
-- Name: log_service_package_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_service_package_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  changes_json JSONB;
  previous_json JSONB;
BEGIN
  -- Build changes object
  changes_json := jsonb_build_object(
    'name', NEW.name,
    'price', NEW.price,
    'promotion_price', NEW.promotion_price,
    'active', NEW.active,
    'updated_at', NEW.updated_at
  );

  -- Build previous values object
  previous_json := jsonb_build_object(
    'name', OLD.name,
    'price', OLD.price,
    'promotion_price', OLD.promotion_price,
    'active', OLD.active
  );

  -- Insert audit log (if we have user context in session)
  IF current_setting('app.user_email', true) IS NOT NULL THEN
    INSERT INTO service_packages_audit_log (
      package_id,
      action,
      changed_by,
      changed_by_email,
      changes,
      previous_values
    ) VALUES (
      NEW.id,
      CASE
        WHEN OLD.active = false AND NEW.active = true THEN 'activate'
        WHEN OLD.active = true AND NEW.active = false THEN 'deactivate'
        WHEN OLD.price != NEW.price OR OLD.promotion_price != NEW.promotion_price THEN 'price_change'
        ELSE 'update'
      END,
      current_setting('app.user_name', true),
      current_setting('app.user_email', true),
      changes_json,
      previous_json
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: FUNCTION log_service_package_update(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.log_service_package_update() IS 'Automatically logs updates to service_packages table';


