--
-- Name: parse_bundle_value(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.parse_bundle_value(bundle_text text) RETURNS numeric
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public'
    AS $$
BEGIN
  IF bundle_text IS NULL OR bundle_text = '' THEN
    RETURN 0;
  END IF;
  
  -- Extract numeric value from strings like "20.0GB", "500min", "100sms"
  RETURN COALESCE(
    (regexp_match(bundle_text, '([0-9]+\.?[0-9]*)'))[1]::DECIMAL,
    0
  );
END;
$$;


--
-- Name: record_email_version_metrics(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_email_version_metrics(p_version_id uuid, p_metric_type text, p_count integer DEFAULT 1) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE email_template_versions
  SET
    sent_count = CASE WHEN p_metric_type = 'sent' THEN sent_count + p_count ELSE sent_count END,
    open_count = CASE WHEN p_metric_type = 'open' THEN open_count + p_count ELSE open_count END,
    click_count = CASE WHEN p_metric_type = 'click' THEN click_count + p_count ELSE click_count END,
    bounce_count = CASE WHEN p_metric_type = 'bounce' THEN bounce_count + p_count ELSE bounce_count END,
    unsubscribe_count = CASE WHEN p_metric_type = 'unsubscribe' THEN unsubscribe_count + p_count ELSE unsubscribe_count END,
    updated_at = now()
  WHERE id = p_version_id;
END;
$$;


--
-- Name: record_oauth_failure(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_oauth_failure(p_integration_slug text, p_error_message text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_updated BOOLEAN;
  v_consecutive_failures INTEGER;
BEGIN
  UPDATE integration_oauth_tokens
  SET
    last_error = p_error_message,
    last_error_at = NOW(),
    consecutive_failures = consecutive_failures + 1,
    updated_at = NOW()
  WHERE integration_slug = p_integration_slug
  AND is_active = true
  RETURNING consecutive_failures INTO v_consecutive_failures;

  v_updated := FOUND;

  -- Log activity
  IF v_updated THEN
    PERFORM log_integration_activity(
      p_integration_slug,
      'oauth_token_refreshed',
      format('Access token refresh failed (attempt %s)', v_consecutive_failures),
      NULL,  -- System action
      'failed',
      p_error_message
    );

    -- Update integration health if too many failures
    IF v_consecutive_failures >= 3 THEN
      UPDATE integration_registry
      SET
        health_status = 'down',
        last_health_check_at = NOW()
      WHERE slug = p_integration_slug;
    END IF;
  END IF;

  RETURN v_updated;
END;
$$;


--
-- Name: FUNCTION record_oauth_failure(p_integration_slug text, p_error_message text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.record_oauth_failure(p_integration_slug text, p_error_message text) IS 'Record OAuth token refresh failure and update health status';


--
-- Name: record_oauth_rate_limit(text, interval); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_oauth_rate_limit(p_integration_slug text, p_cooldown_duration interval DEFAULT '00:05:00'::interval) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_updated BOOLEAN;
  v_cooldown_until TIMESTAMPTZ;
BEGIN
  v_cooldown_until := NOW() + p_cooldown_duration;

  UPDATE integration_oauth_tokens
  SET
    rate_limit_cooldown_until = v_cooldown_until,
    rate_limit_hits = rate_limit_hits || jsonb_build_object('timestamp', NOW()),
    updated_at = NOW()
  WHERE integration_slug = p_integration_slug
  AND is_active = true;

  v_updated := FOUND;

  -- Log activity
  IF v_updated THEN
    PERFORM log_integration_activity(
      p_integration_slug,
      'oauth_token_refreshed',
      format('Rate limit hit. Cooldown until %s', v_cooldown_until),
      NULL,
      'partial',
      'Too many OAuth refresh requests'
    );

    -- Update integration health
    UPDATE integration_registry
    SET
      health_status = 'degraded',
      last_health_check_at = NOW()
    WHERE slug = p_integration_slug;
  END IF;

  RETURN v_updated;
END;
$$;


--
-- Name: FUNCTION record_oauth_rate_limit(p_integration_slug text, p_cooldown_duration interval); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.record_oauth_rate_limit(p_integration_slug text, p_cooldown_duration interval) IS 'Record rate limit hit with cooldown period';


--
-- Name: record_rate_limit_hit(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_rate_limit_hit(p_service_package_id uuid, p_api_type text, p_error_message text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_hit_record JSONB;
BEGIN
  -- Build hit record
  v_hit_record := jsonb_build_object(
    'timestamp', NOW(),
    'api_type', p_api_type,
    'error_message', p_error_message
  );

  -- Update product_integrations
  UPDATE product_integrations
  SET
    rate_limit_hits = COALESCE(rate_limit_hits, '[]'::jsonb) || v_hit_record,
    last_rate_limit_at = NOW()
  WHERE service_package_id = p_service_package_id;

  -- Log to zoho_sync_logs if table exists
  BEGIN
    INSERT INTO zoho_sync_logs (
      entity_type,
      entity_id,
      status,
      error_message,
      metadata
    ) VALUES (
      'service_package',
      p_service_package_id,
      'rate_limit',
      p_error_message,
      jsonb_build_object(
        'api_type', p_api_type,
        'hit_at', NOW()
      )
    );
  EXCEPTION
    WHEN undefined_table THEN
      NULL; -- zoho_sync_logs table doesn't exist yet
  END;
END;
$$;


--
-- Name: reject_admin_access_request(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reject_admin_access_request(p_request_id uuid, p_reason text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_request pending_admin_users;
BEGIN
  -- Get the pending request
  SELECT * INTO v_request
  FROM pending_admin_users
  WHERE id = p_request_id
  AND status = 'pending';

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Request not found or already processed'
    );
  END IF;

  -- Update request status
  UPDATE pending_admin_users
  SET
    status = 'rejected',
    reviewed_by = auth.uid(),
    reviewed_at = NOW(),
    rejection_reason = p_reason
  WHERE id = p_request_id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'Request rejected successfully'
  );
END;
$$;


