--
-- Name: suggest_zones_from_demographics(numeric, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.suggest_zones_from_demographics(p_min_fit_score numeric DEFAULT 50, p_province text DEFAULT NULL::text, p_limit integer DEFAULT 20) RETURNS TABLE(ward_code text, ward_name text, municipality text, province text, centroid_lat double precision, centroid_lng double precision, demographic_fit_score numeric, pct_no_internet numeric, pct_income_above_r12800 numeric, total_population integer, total_households integer, business_poi_count integer, nearby_base_stations bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  RETURN QUERY SELECT
    wd.ward_code, wd.ward_name, wd.municipality, wd.province,
    wd.centroid_lat, wd.centroid_lng, wd.demographic_fit_score,
    wd.pct_no_internet, wd.pct_income_above_r12800,
    wd.total_population, wd.total_households, wd.business_poi_count,
    (SELECT COUNT(*) FROM tarana_base_stations tbs
     WHERE wd.centroid_lat IS NOT NULL AND wd.centroid_lng IS NOT NULL
       AND ST_DWithin(tbs.location::GEOGRAPHY,
         ST_SetSRID(ST_MakePoint(wd.centroid_lng, wd.centroid_lat), 4326)::GEOGRAPHY, 5000)
    ) AS nearby_base_stations
  FROM ward_demographics wd
  WHERE wd.demographic_fit_score >= p_min_fit_score
    AND (p_province IS NULL OR wd.province = p_province)
    AND wd.centroid_lat IS NOT NULL AND wd.centroid_lng IS NOT NULL
  ORDER BY wd.demographic_fit_score DESC LIMIT p_limit;
END; $$;


--
-- Name: sync_customer_email_verified(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_customer_email_verified() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  BEGIN
    -- When auth.users email is confirmed, update customer record
    -- This runs with elevated privileges to bypass RLS
    IF NEW.email_confirmed_at IS NOT NULL AND
       (OLD IS NULL OR OLD.email_confirmed_at IS NULL OR OLD.email_confirmed_at != NEW.email_confirmed_at) THEN

      -- Update customers table (bypasses RLS due to SECURITY DEFINER)
      UPDATE customers
      SET
        email_verified = TRUE,
        updated_at = NOW()
      WHERE auth_user_id = NEW.id;

      -- Log for debugging (optional)
      RAISE NOTICE 'Email verified for user: %', NEW.id;
    END IF;

    RETURN NEW;
  END;
  $$;


--
-- Name: sync_customer_friendly_features(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_customer_friendly_features() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  -- If features array exists, create customer_friendly version
  IF NEW.features IS NOT NULL AND array_length(NEW.features, 1) > 0 THEN
    -- Store features with emoji markers for frontend formatting
    NEW.customer_friendly_features := jsonb_build_object(
      'benefits', (
        SELECT jsonb_agg(feature)
        FROM unnest(NEW.features) AS feature
        WHERE lower(feature) LIKE '%free%'
           OR lower(feature) LIKE '%included%'
           OR lower(feature) LIKE '%router%'
           OR lower(feature) LIKE '%installation%'
           OR lower(feature) LIKE '%insured%'
        LIMIT 4
      ),
      'additional_info', (
        SELECT jsonb_agg(feature)
        FROM unnest(NEW.features) AS feature
        WHERE lower(feature) NOT LIKE '%free%'
          AND lower(feature) NOT LIKE '%included%'
          AND lower(feature) NOT LIKE '%router%'
          AND lower(feature) NOT LIKE '%insured%'
        LIMIT 6
      ),
      'all_features', to_jsonb(NEW.features)
    );
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: sync_service_package_pricing(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_service_package_pricing() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  base_slug TEXT;
  slug_counter INTEGER;
BEGIN
  -- If pricing object is updated, sync to root-level fields
  IF NEW.pricing IS NOT NULL THEN
    NEW.base_price_zar := (NEW.pricing->>'monthly')::numeric;
    -- DO NOT overwrite cost_price_zar from pricing.setup
    -- cost_price_zar holds actual monthly wholesale cost, not installation fee
    NEW.price := (NEW.pricing->>'monthly')::numeric;
    NEW.speed_down := COALESCE((NEW.pricing->>'download_speed')::integer, 0);
    NEW.speed_up := COALESCE((NEW.pricing->>'upload_speed')::integer, 0);
  END IF;

  -- If root-level fields are updated, sync to pricing object
  IF NEW.base_price_zar IS NOT NULL THEN
    NEW.pricing := jsonb_build_object(
      'monthly', COALESCE(NEW.base_price_zar, NEW.price, 0),
      'setup', COALESCE((NEW.pricing->>'setup')::numeric, 0),
      'download_speed', COALESCE(NEW.speed_down, 0),
      'upload_speed', COALESCE(NEW.speed_up, 0)
    );
  END IF;

  -- Auto-generate unique slug if not provided
  IF NEW.slug IS NULL OR NEW.slug = '' THEN
    base_slug := LOWER(
      REGEXP_REPLACE(
        REGEXP_REPLACE(NEW.name, '[^a-zA-Z0-9\s-]', '', 'g'),
        '\s+', '-', 'g'
      )
    );

    SELECT COUNT(*) + 1 INTO slug_counter
    FROM service_packages
    WHERE slug LIKE base_slug || '%'
      AND (TG_OP = 'INSERT' OR id != NEW.id);

    IF slug_counter > 1 THEN
      NEW.slug := base_slug || '-' || slug_counter;
    ELSE
      NEW.slug := base_slug;
    END IF;
  END IF;

  -- Sync status to active boolean
  NEW.active := (NEW.status = 'active');

  RETURN NEW;
END;
$$;


--
-- Name: track_status_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.track_status_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF (TG_OP = 'INSERT') OR (OLD.status IS DISTINCT FROM NEW.status) THEN
    INSERT INTO order_status_history (
      entity_type,
      entity_id,
      old_status,
      new_status,
      automated
    ) VALUES (
      TG_TABLE_NAME::TEXT,
      NEW.id,
      OLD.status,
      NEW.status,
      true
    );
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trigger_kyc_session(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trigger_kyc_session() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_flow_type TEXT;
  v_user_type TEXT;
BEGIN
  -- Only create KYC session when quote status changes to 'approved'
  IF NEW.status = 'approved' AND (OLD.status IS NULL OR OLD.status != 'approved') THEN

    -- Determine flow type based on quote total
    -- Calculate total contract value (monthly * term + installation)
    IF (NEW.total_monthly * NEW.contract_term + NEW.total_installation) < 500000 THEN
      v_flow_type := 'sme_light';
    ELSE
      v_flow_type := 'full_kyc';
    END IF;

    -- Determine user type based on customer_type
    IF NEW.customer_type IN ('smme', 'enterprise') THEN
      v_user_type := 'business';
    ELSE
      v_user_type := 'consumer';
    END IF;

    -- Create KYC session placeholder
    -- Note: The actual didit_session_id will be set by the API when creating Didit session
    INSERT INTO kyc_sessions (
      quote_id,
      didit_session_id,
      flow_type,
      user_type,
      status
    ) VALUES (
      NEW.id,
      'pending_' || NEW.id::TEXT, -- Temporary ID, will be replaced by API
      v_flow_type,
      v_user_type,
      'not_started'
    )
    ON CONFLICT (didit_session_id) DO NOTHING; -- Prevent duplicates

  END IF;

  RETURN NEW;
END;
$$;


