--
-- Name: update_corporate_site_counts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_corporate_site_counts() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  corp_id UUID;
BEGIN
  -- Determine which corporate to update
  IF TG_OP = 'DELETE' THEN
    corp_id := OLD.corporate_id;
  ELSE
    corp_id := NEW.corporate_id;
  END IF;

  -- Update counts
  UPDATE corporate_accounts
  SET
    total_sites = (
      SELECT COUNT(*) FROM corporate_sites
      WHERE corporate_id = corp_id
    ),
    active_sites = (
      SELECT COUNT(*) FROM corporate_sites
      WHERE corporate_id = corp_id AND status = 'active'
    ),
    pending_sites = (
      SELECT COUNT(*) FROM corporate_sites
      WHERE corporate_id = corp_id AND status IN ('pending', 'ready', 'provisioned')
    ),
    updated_at = NOW()
  WHERE id = corp_id;

  RETURN COALESCE(NEW, OLD);
END;
$$;


