--
-- Name: update_field_jobs_timestamp(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_field_jobs_timestamp() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
    NEW.updated_at = NOW();
    
    -- Auto-set started_at when status changes to in_progress
    IF NEW.status = 'in_progress' AND OLD.status != 'in_progress' AND NEW.started_at IS NULL THEN
        NEW.started_at = NOW();
    END IF;
    
    -- Auto-set completed_at when status changes to completed
    IF NEW.status = 'completed' AND OLD.status != 'completed' AND NEW.completed_at IS NULL THEN
        NEW.completed_at = NOW();
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: update_installation_tasks_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_installation_tasks_updated_at() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.updated_at = NOW();
  NEW.updated_by = auth.uid();

  -- Update technician statistics when task is completed
  IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
    UPDATE public.technicians
    SET completed_installations = completed_installations + 1
    WHERE id = NEW.technician_id;

    -- Calculate actual duration if not set
    IF NEW.actual_duration_minutes IS NULL AND NEW.started_at IS NOT NULL THEN
      NEW.actual_duration_minutes = EXTRACT(EPOCH FROM (NEW.completed_at - NEW.started_at)) / 60;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: update_integration_health(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_integration_health() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_health_status TEXT;
  v_success_rate DECIMAL(5,2);
BEGIN
  -- Calculate success rate from last hour
  SELECT
    CASE
      WHEN total_requests = 0 THEN 100.00
      ELSE ROUND((successful_requests::DECIMAL / total_requests::DECIMAL) * 100, 2)
    END
  INTO v_success_rate
  FROM integration_api_metrics
  WHERE integration_slug = NEW.integration_slug
  AND created_at >= NOW() - INTERVAL '1 hour'
  ORDER BY created_at DESC
  LIMIT 1;

  -- Determine health status
  v_health_status := CASE
    WHEN v_success_rate >= 95 THEN 'healthy'
    WHEN v_success_rate >= 80 THEN 'degraded'
    ELSE 'down'
  END;

  -- Update integration registry
  UPDATE integration_registry
  SET
    health_status = v_health_status,
    last_health_check_at = NOW(),
    avg_response_time_ms = NEW.avg_response_time_ms,
    updated_at = NOW()
  WHERE slug = NEW.integration_slug;

  RETURN NEW;
END;
$$;


