--
-- Name: update_oauth_access_token(text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_oauth_access_token(p_integration_slug text, p_access_token text, p_expires_at timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_updated BOOLEAN;
BEGIN
  UPDATE integration_oauth_tokens
  SET
    access_token = p_access_token,
    expires_at = p_expires_at,
    last_refreshed_at = NOW(),
    refresh_count = refresh_count + 1,
    consecutive_failures = 0,  -- Reset failures on success
    last_error = NULL,
    last_error_at = NULL,
    updated_at = NOW()
  WHERE integration_slug = p_integration_slug
  AND is_active = true;

  v_updated := FOUND;

  -- Log activity
  IF v_updated THEN
    PERFORM log_integration_activity(
      p_integration_slug,
      'oauth_token_refreshed',
      'Access token refreshed successfully',
      NULL,  -- System action
      'success',
      NULL
    );
  END IF;

  RETURN v_updated;
END;
$$;


--
-- Name: FUNCTION update_oauth_access_token(p_integration_slug text, p_access_token text, p_expires_at timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_oauth_access_token(p_integration_slug text, p_access_token text, p_expires_at timestamp with time zone) IS 'Update access token after successful OAuth refresh';


