-- Name: update_order_communications_updated_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_order_communications_updated_at() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.updated_at = NOW();

  -- Auto-set timestamps based on status changes
  IF NEW.status = 'sent' AND OLD.status != 'sent' THEN
    NEW.sent_at = NOW();
  ELSIF NEW.status = 'delivered' AND OLD.status != 'delivered' THEN
    NEW.delivered_at = NOW();
  ELSIF NEW.status = 'opened' AND OLD.status != 'opened' THEN
    NEW.opened_at = NOW();
  ELSIF NEW.status = 'failed' AND OLD.status != 'failed' THEN
    NEW.failed_at = NOW();
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: update_order_fulfillment_status(uuid, character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
