CREATE FUNCTION public.update_order_fulfillment_status(p_order_id uuid, p_fulfillment_status character varying, p_event_title character varying, p_event_description text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Update order status
  UPDATE public.orders
  SET
    fulfillment_status = p_fulfillment_status,
