  WHERE id = p_order_id;

  -- Add tracking event
  PERFORM add_order_tracking_event(
    p_order_id,
    p_fulfillment_status,
    'completed',
    p_event_title,
    p_event_description,
    NULL,
    NULL,
    TRUE
  );
END;
$$;


