  RETURN NEW;
END;
$$;


--
-- Name: update_technician_location(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_technician_location() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
    UPDATE technicians
    SET 
        current_latitude = NEW.latitude,
        current_longitude = NEW.longitude,
        current_location_accuracy = NEW.accuracy,
        location_updated_at = NEW.recorded_at
    WHERE id = NEW.technician_id;
    
    RETURN NEW;
END;
$$;


