--
-- Name: update_whatsapp_message_status(text, text, integer, text, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_whatsapp_message_status(p_message_id text, p_status text, p_error_code integer DEFAULT NULL::integer, p_error_message text DEFAULT NULL::text, p_billable boolean DEFAULT NULL::boolean, p_pricing_category text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE whatsapp_message_log
  SET
    status = p_status,
    status_updated_at = now(),
    error_code = COALESCE(p_error_code, error_code),
    error_message = COALESCE(p_error_message, error_message),
    billable = COALESCE(p_billable, billable),
    pricing_category = COALESCE(p_pricing_category, pricing_category)
  WHERE message_id = p_message_id;

  RETURN FOUND;
END;
$$;


