CREATE VIEW public.admin_user_permissions WITH (security_invoker='on') AS
 SELECT au.id,
    au.email,
    au.full_name,
    au.role,
    au.role_template_id,
    rt.name AS role_template_name,
    au.department,
    au.job_title,
    public.get_user_permissions(au.id) AS effective_permissions,
    au.custom_permissions,
    rt.permissions AS template_permissions
   FROM (public.admin_users au
     LEFT JOIN public.role_templates rt ON ((rt.id = au.role_template_id)));


