-- Name: TABLE business_journey_stages; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.business_journey_stages IS 'Tracks B2B customer progress through 6-step onboarding journey';


--
-- Name: COLUMN business_journey_stages.stage; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.business_journey_stages.stage IS 'Current stage in the journey (1-6)';


--
-- Name: COLUMN business_journey_stages.required_documents; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.business_journey_stages.required_documents IS 'JSON array of document types required for this stage';


--
-- Name: business_journey_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.business_journey_summary WITH (security_invoker='on') AS
 SELECT bc.id AS business_customer_id,
    bc.company_name,
    bc.account_number,
    bc.account_status,
    bc.kyc_status,
    bjs.quote_id,
    ( SELECT business_journey_stages.stage
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = ANY (ARRAY['pending'::public.journey_stage_status, 'in_progress'::public.journey_stage_status, 'blocked'::public.journey_stage_status])))
          ORDER BY business_journey_stages.step_number
         LIMIT 1) AS current_stage,
    ( SELECT business_journey_stages.step_number
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = ANY (ARRAY['pending'::public.journey_stage_status, 'in_progress'::public.journey_stage_status, 'blocked'::public.journey_stage_status])))
          ORDER BY business_journey_stages.step_number
         LIMIT 1) AS current_step,
    ( SELECT count(*) AS count
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = 'completed'::public.journey_stage_status))) AS completed_stages,
    6 AS total_stages,
    round((((( SELECT count(*) AS count
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = 'completed'::public.journey_stage_status))))::numeric / (6)::numeric) * (100)::numeric)) AS progress_percentage,
    (EXISTS ( SELECT 1
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = 'blocked'::public.journey_stage_status)))) AS is_blocked,
    ( SELECT business_journey_stages.stage
           FROM public.business_journey_stages
          WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = 'blocked'::public.journey_stage_status))
         LIMIT 1) AS blocked_stage,
    ( SELECT min(business_journey_stages.started_at) AS min
           FROM public.business_journey_stages
          WHERE (business_journey_stages.business_customer_id = bc.id)) AS journey_started_at,
        CASE
            WHEN (( SELECT count(*) AS count
               FROM public.business_journey_stages
              WHERE ((business_journey_stages.business_customer_id = bc.id) AND (business_journey_stages.status = 'completed'::public.journey_stage_status))) = 6) THEN ( SELECT max(business_journey_stages.completed_at) AS max
               FROM public.business_journey_stages
              WHERE (business_journey_stages.business_customer_id = bc.id))
            ELSE NULL::timestamp with time zone
        END AS journey_completed_at,
    bc.created_at,
    bc.updated_at
   FROM (public.business_customers bc
     LEFT JOIN public.business_journey_stages bjs ON ((bc.id = bjs.business_customer_id)))
  GROUP BY bc.id, bc.company_name, bc.account_number, bc.account_status, bc.kyc_status, bjs.quote_id, bc.created_at, bc.updated_at;


