    CONSTRAINT contracts_contract_type_check CHECK ((contract_type = ANY (ARRAY['fibre'::text, 'wireless'::text, 'hybrid'::text]))),
    CONSTRAINT contracts_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'pending_signature'::text, 'partially_signed'::text, 'fully_signed'::text, 'active'::text, 'expired'::text, 'terminated'::text])))
);


