--
-- Name: contribution_margins; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.contribution_margins (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    product_id uuid NOT NULL,
    financial_period_id uuid NOT NULL,
    revenue_zar numeric(15,2) NOT NULL,
    variable_costs_zar numeric(15,2) NOT NULL,
    contribution_margin_zar numeric(15,2) GENERATED ALWAYS AS ((revenue_zar - variable_costs_zar)) STORED,
    margin_percentage numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (revenue_zar > (0)::numeric) THEN (((revenue_zar - variable_costs_zar) / revenue_zar) * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    created_at timestamp with time zone DEFAULT now()
);


