    endpoint character varying(255) NOT NULL,
    method character varying(10) DEFAULT 'POST'::character varying NOT NULL,
    address text,
    latitude numeric(10,8),
    longitude numeric(11,8),
    province character varying(100),
    city character varying(100),
    coverage_type character varying(50),
    provider_code character varying(50),
    provider_name character varying(100),
    status_code integer NOT NULL,
    success boolean DEFAULT false NOT NULL,
    response_time_ms integer NOT NULL,
    has_coverage boolean,
    coverage_status character varying(50),
    packages_found integer DEFAULT 0,
    error_code character varying(100),
    error_message text,
    error_type character varying(100),
    lead_id uuid,
    session_id character varying(100),
    user_agent text,
    ip_address inet,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT valid_coordinates CHECK ((((latitude IS NULL) AND (longitude IS NULL)) OR (((latitude >= ('-90'::integer)::numeric) AND (latitude <= (90)::numeric)) AND ((longitude >= ('-180'::integer)::numeric) AND (longitude <= (180)::numeric)))))
);


