CREATE SEQUENCE public.credit_note_number_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


--
-- Name: credit_notes; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.credit_notes (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    credit_note_number character varying(20) NOT NULL,
    original_invoice_id uuid NOT NULL,
    customer_id uuid NOT NULL,
    credit_note_date date DEFAULT CURRENT_DATE NOT NULL,
    subtotal numeric(10,2) NOT NULL,
    vat_rate numeric(5,2) DEFAULT 15.00 NOT NULL,
    vat_amount numeric(10,2) NOT NULL,
    total_amount numeric(10,2) NOT NULL,
    line_items jsonb DEFAULT '[]'::jsonb NOT NULL,
    reason text NOT NULL,
    reason_category character varying(50) NOT NULL,
    status character varying(20) DEFAULT 'draft'::character varying NOT NULL,
    applied_at timestamp with time zone,
    pdf_url text,
    pdf_generated_at timestamp with time zone,
    notes text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT credit_notes_amounts_positive CHECK (((subtotal >= (0)::numeric) AND (vat_amount >= (0)::numeric) AND (total_amount >= (0)::numeric))),
    CONSTRAINT credit_notes_reason_category_check CHECK (((reason_category)::text = ANY ((ARRAY['billing_error'::character varying, 'service_issue'::character varying, 'cancellation'::character varying, 'price_adjustment'::character varying, 'duplicate'::character varying, 'other'::character varying])::text[]))),
    CONSTRAINT credit_notes_status_check CHECK (((status)::text = ANY ((ARRAY['draft'::character varying, 'issued'::character varying, 'applied'::character varying])::text[])))
);


--
-- Name: TABLE credit_notes; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.credit_notes IS 'Credit notes for reversing/correcting invoices. Required for SARS compliance - invoices cannot be edited once issued.';


--
-- Name: cron_execution_log; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.cron_execution_log (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    job_name character varying(100) NOT NULL,
    execution_start timestamp with time zone DEFAULT now() NOT NULL,
    execution_end timestamp with time zone,
    duration_seconds integer GENERATED ALWAYS AS ((EXTRACT(epoch FROM (execution_end - execution_start)))::integer) STORED,
    status character varying(20) DEFAULT 'running'::character varying NOT NULL,
    records_processed integer DEFAULT 0,
    records_failed integer DEFAULT 0,
    records_skipped integer DEFAULT 0,
    error_message text,
    error_details jsonb,
    trigger_source character varying(50) DEFAULT 'vercel_cron'::character varying,
    triggered_by uuid,
    environment character varying(20),
    execution_details jsonb,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT cron_execution_log_records_check CHECK (((records_processed >= 0) AND (records_failed >= 0) AND (records_skipped >= 0))),
    CONSTRAINT cron_execution_log_status_check CHECK (((status)::text = ANY ((ARRAY['running'::character varying, 'completed'::character varying, 'failed'::character varying, 'partial'::character varying, 'cancelled'::character varying])::text[]))),
    CONSTRAINT cron_execution_log_trigger_source_check CHECK (((trigger_source)::text = ANY ((ARRAY['vercel_cron'::character varying, 'manual'::character varying, 'api'::character varying, 'scheduled'::character varying])::text[])))
);


--
-- Name: TABLE cron_execution_log; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.cron_execution_log IS 'Tracks execution of scheduled cron jobs with timing, results, and error handling';


--
-- Name: COLUMN cron_execution_log.job_name; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.cron_execution_log.job_name IS 'Cron job identifier: generate_invoices, sync_usage_data, process_debit_orders, etc.';


--
-- Name: COLUMN cron_execution_log.duration_seconds; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.cron_execution_log.duration_seconds IS 'Computed column: execution time in seconds (execution_end - execution_start)';


