    amount_paid numeric(10,2) DEFAULT 0.00,
    amount_due numeric(10,2) NOT NULL,
    status character varying(50) DEFAULT 'draft'::character varying NOT NULL,
    paid_at timestamp with time zone,
    zoho_invoice_id character varying(100),
    zoho_pdf_url text,
    line_items jsonb,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    zoho_billing_invoice_id text,
    zoho_sync_status text DEFAULT 'pending'::text,
    zoho_last_synced_at timestamp with time zone,
    zoho_last_sync_error text,
    is_locked boolean DEFAULT false,
    locked_at timestamp with time zone,
    locked_reason text,
    voided_at timestamp with time zone,
    voided_by uuid,
    void_reason text,
    emailed_at timestamp with time zone,
    email_attempts integer DEFAULT 0,
    period_start date,
    period_end date,
    service_id uuid,
    invoice_type character varying(50) DEFAULT 'recurring'::character varying,
    vat_rate numeric(5,2) DEFAULT 15.00,
    notes text,
    reminder_sent_at timestamp with time zone,
    reminder_count integer DEFAULT 0,
    reminder_error text,
    paynow_url text,
    paynow_transaction_ref character varying(100),
    paynow_sent_at timestamp with time zone,
    paynow_sent_via text[] DEFAULT '{}'::text[],
    payment_collection_method character varying(50),
    debit_order_failed_at timestamp with time zone,
    debit_order_failure_reason text,
    whatsapp_sent_at timestamp with time zone,
    whatsapp_message_id text,
    zoho_books_invoice_id text,
    zoho_books_retry_count integer DEFAULT 0,
    zoho_books_next_retry_at timestamp with time zone,
    corporate_account_id uuid,
    corporate_site_id uuid,
    CONSTRAINT valid_invoice_status CHECK (((status)::text = ANY ((ARRAY['draft'::character varying, 'sent'::character varying, 'paid'::character varying, 'partial'::character varying, 'overdue'::character varying, 'cancelled'::character varying, 'voided'::character varying])::text[])))
);


