    setup_fee numeric(10,2) DEFAULT 0,
    status character varying(50) DEFAULT 'pending'::character varying NOT NULL,
    active boolean DEFAULT true,
    installation_address text,
    installation_date date,
    activation_date date,
    speed_down integer,
    speed_up integer,
    data_cap_gb integer,
    provider_code character varying(50),
    provider_name character varying(100),
    contract_months integer DEFAULT 0,
    contract_start_date date,
    contract_end_date date,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    cancelled_at timestamp with time zone,
    zoho_subscription_id text,
    zoho_sync_status text DEFAULT 'pending'::text,
    zoho_last_synced_at timestamp with time zone,
    zoho_last_sync_error text,
    connection_id character varying(100),
    billing_day integer DEFAULT 1,
    last_invoice_date date,
    CONSTRAINT customer_services_billing_day_check CHECK (((billing_day >= 1) AND (billing_day <= 28))),
    CONSTRAINT valid_status CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'active'::character varying, 'suspended'::character varying, 'cancelled'::character varying])::text[])))
);


