-- Name: customers; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.customers (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    first_name character varying(100) NOT NULL,
    last_name character varying(100) NOT NULL,
    email character varying(255) NOT NULL,
    phone character varying(20) NOT NULL,
    id_number character varying(20),
    email_verified boolean DEFAULT false,
    status character varying(50) DEFAULT 'active'::character varying,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    account_type text DEFAULT 'personal'::text NOT NULL,
    location_type public.location_type_enum,
    auth_user_id uuid,
    password_reset_token text,
    password_reset_expires_at timestamp with time zone,
    last_login timestamp with time zone,
    business_name character varying(255),
    business_registration character varying(100),
    tax_number character varying(100),
    account_number character varying(20),
    account_status character varying(20) DEFAULT 'active'::character varying,
    zoho_billing_customer_id text,
    zoho_sync_status text DEFAULT 'pending'::text,
    zoho_last_synced_at timestamp with time zone,
    zoho_last_sync_error text,
    phone_verified_at timestamp with time zone,
    whatsapp_consent boolean DEFAULT false,
    whatsapp_consent_at timestamp with time zone,
    whatsapp_consent_source text,
    zoho_books_contact_id text,
    zoho_books_retry_count integer DEFAULT 0,
    zoho_books_next_retry_at timestamp with time zone,
    corporate_site_id uuid,
    CONSTRAINT customers_account_status_check CHECK (((account_status)::text = ANY ((ARRAY['active'::character varying, 'suspended'::character varying, 'cancelled'::character varying, 'pending'::character varying])::text[]))),
    CONSTRAINT customers_account_type_check CHECK ((account_type = ANY (ARRAY['personal'::text, 'business'::text, 'internal_test'::text]))),
    CONSTRAINT customers_whatsapp_consent_source_check CHECK (((whatsapp_consent_source IS NULL) OR (whatsapp_consent_source = ANY (ARRAY['signup'::text, 'sms_optin'::text, 'admin_import'::text, 'order_form'::text, 'partner_registration'::text]))))
);


