--
-- Name: orders; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.orders (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    customer_id uuid,
    lead_id uuid,
    package_id character varying(255) NOT NULL,
    status character varying(50) DEFAULT 'pending'::character varying,
    order_type character varying(50) DEFAULT 'fiber'::character varying,
    installation_address text,
    coordinates jsonb,
    installation_date date,
    notes text,
    total_amount numeric(10,2),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    customer_name character varying(255),
    customer_email character varying(255),
    customer_phone character varying(50),
    service_type character varying(100),
    speed_down integer,
    speed_up integer,
    base_price numeric(10,2),
    promotional_price numeric(10,2),
    promotional_months integer,
    installation_fee numeric(10,2) DEFAULT 0.00,
    payment_status character varying(50) DEFAULT 'pending'::character varying,
    payment_method character varying(50) DEFAULT 'netcash'::character varying,
    payment_reference character varying(255),
    netcash_transaction_id character varying(255),
    payment_date timestamp with time zone,
    order_status character varying(50) DEFAULT 'pending_payment'::character varying,
    crm_synced boolean DEFAULT false,
    crm_lead_id character varying(255),
    crm_synced_at timestamp with time zone,
    customer_notes text,
    internal_notes text,
    installation_location_type public.location_type_enum,
    fulfillment_status character varying(50) DEFAULT 'order_confirmed'::character varying,
    delivery_status character varying(50),
    delivery_tracking_number character varying(255),
    delivery_carrier character varying(100),
    delivery_date timestamp with time zone,
    site_survey_scheduled_date timestamp with time zone,
    site_survey_completed_date timestamp with time zone,
    site_survey_status character varying(50),
    site_survey_notes text,
    installation_scheduled_date timestamp with time zone,
    installation_completed_date timestamp with time zone,
    installation_technician character varying(255),
    installation_notes text,
    activation_date timestamp with time zone,
    billing_start_date timestamp with time zone,
    expected_completion_date timestamp with time zone,
    CONSTRAINT orders_valid_order_status CHECK (((order_status)::text = ANY ((ARRAY['pending_payment'::character varying, 'payment_received'::character varying, 'crm_processing'::character varying, 'confirmed'::character varying, 'cancelled'::character varying, 'failed'::character varying])::text[]))),
    CONSTRAINT orders_valid_payment_status CHECK (((payment_status)::text = ANY ((ARRAY['pending'::character varying, 'processing'::character varying, 'completed'::character varying, 'failed'::character varying, 'refunded'::character varying, 'cancelled'::character varying])::text[]))),
    CONSTRAINT valid_delivery_status CHECK (((delivery_status IS NULL) OR ((delivery_status)::text = ANY ((ARRAY['pending'::character varying, 'prepared'::character varying, 'shipped'::character varying, 'in_transit'::character varying, 'out_for_delivery'::character varying, 'delivered'::character varying, 'failed'::character varying, 'returned'::character varying])::text[])))),
    CONSTRAINT valid_fulfillment_status CHECK (((fulfillment_status)::text = ANY ((ARRAY['order_confirmed'::character varying, 'equipment_prepared'::character varying, 'shipped'::character varying, 'out_for_delivery'::character varying, 'delivered'::character varying, 'site_survey_scheduled'::character varying, 'site_survey_completed'::character varying, 'installation_scheduled'::character varying, 'installation_in_progress'::character varying, 'installation_completed'::character varying, 'activation_scheduled'::character varying, 'service_activated'::character varying, 'completed'::character varying, 'cancelled'::character varying])::text[]))),
    CONSTRAINT valid_order_type CHECK (((order_type)::text = ANY ((ARRAY['fiber'::character varying, 'wireless'::character varying, 'lte'::character varying, '5g'::character varying])::text[]))),
    CONSTRAINT valid_site_survey_status CHECK (((site_survey_status IS NULL) OR ((site_survey_status)::text = ANY ((ARRAY['scheduled'::character varying, 'in_progress'::character varying, 'passed'::character varying, 'failed'::character varying, 'rescheduled'::character varying])::text[]))))
);


