--
-- Name: customer_dashboard_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.customer_dashboard_summary WITH (security_invoker='on') AS
 SELECT c.id AS customer_id,
    c.email,
    c.first_name,
    c.last_name,
    c.phone,
    c.created_at AS customer_since,
    ( SELECT count(*) AS count
           FROM public.customer_services
          WHERE ((customer_services.customer_id = c.id) AND (customer_services.active = true))) AS active_services_count,
    ( SELECT json_build_object('id', cs.id, 'package_name', cs.package_name, 'service_type', cs.service_type, 'status', cs.status, 'monthly_price', cs.monthly_price, 'installation_address', cs.installation_address, 'speed_down', cs.speed_down, 'speed_up', cs.speed_up) AS json_build_object
           FROM public.customer_services cs
          WHERE ((cs.customer_id = c.id) AND (cs.active = true))
          ORDER BY cs.created_at DESC
         LIMIT 1) AS primary_service,
    ( SELECT json_build_object('account_balance', cb.account_balance, 'payment_method', cb.payment_method, 'payment_status', cb.payment_status, 'next_billing_date', cb.next_billing_date, 'days_overdue', cb.days_overdue) AS json_build_object
           FROM public.customer_billing cb
          WHERE (cb.customer_id = c.id)) AS billing_info,
    ( SELECT count(*) AS count
           FROM public.orders
          WHERE (orders.customer_id = c.id)) AS total_orders,
    ( SELECT count(*) AS count
           FROM public.orders
          WHERE ((orders.customer_id = c.id) AND ((orders.status)::text = 'pending'::text))) AS pending_orders,
    ( SELECT count(*) AS count
           FROM public.customer_invoices
          WHERE ((customer_invoices.customer_id = c.id) AND ((customer_invoices.status)::text = 'overdue'::text))) AS overdue_invoices
   FROM public.customers c;


