CREATE TABLE public.email_template_versions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    template_id text NOT NULL,
    version_name text NOT NULL,
    subject_template text NOT NULL,
    slice_composition jsonb DEFAULT '[]'::jsonb NOT NULL,
    is_active boolean DEFAULT false,
    is_winner boolean DEFAULT false,
    sent_count integer DEFAULT 0,
    open_count integer DEFAULT 0,
    click_count integer DEFAULT 0,
    bounce_count integer DEFAULT 0,
    unsubscribe_count integer DEFAULT 0,
    open_rate numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (sent_count > 0) THEN (((open_count)::numeric / (sent_count)::numeric) * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    click_rate numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (sent_count > 0) THEN (((click_count)::numeric / (sent_count)::numeric) * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    test_start_date timestamp with time zone,
    test_end_date timestamp with time zone,
    traffic_percentage integer,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    created_by uuid,
    CONSTRAINT email_template_versions_traffic_percentage_check CHECK (((traffic_percentage >= 0) AND (traffic_percentage <= 100)))
);


