    CONSTRAINT kyc_sessions_status_check CHECK ((status = ANY (ARRAY['not_started'::text, 'in_progress'::text, 'completed'::text, 'abandoned'::text, 'declined'::text]))),
    CONSTRAINT kyc_sessions_user_type_check CHECK ((user_type = ANY (ARRAY['business'::text, 'consumer'::text]))),
    CONSTRAINT kyc_sessions_verification_result_check CHECK ((verification_result = ANY (ARRAY['approved'::text, 'declined'::text, 'pending_review'::text])))
);


