--
-- Name: lead_scores; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.lead_scores (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    coverage_lead_id uuid,
    zone_id uuid,
    product_fit_score integer DEFAULT 0,
    revenue_potential_score integer DEFAULT 0,
    competitive_vuln_score integer DEFAULT 0,
    conversion_speed_score integer DEFAULT 0,
    composite_score numeric(5,2) GENERATED ALWAYS AS ((((((product_fit_score)::numeric * 0.35) + ((revenue_potential_score)::numeric * 0.30)) + ((competitive_vuln_score)::numeric * 0.20)) + ((conversion_speed_score)::numeric * 0.15))) STORED,
    recommended_product text,
    recommended_track text,
    estimated_mrr numeric(10,2),
    competitor_identified text,
    scoring_date timestamp with time zone DEFAULT now(),
    scored_by text DEFAULT 'system'::text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    nearest_base_station_km double precision,
    skyfibre_confidence text,
    nearest_dfa_building_km double precision,
    dfa_coverage_type text,
    coverage_product_eligible text[],
    CONSTRAINT lead_scores_competitive_vuln_score_check CHECK (((competitive_vuln_score >= 0) AND (competitive_vuln_score <= 100))),
    CONSTRAINT lead_scores_conversion_speed_score_check CHECK (((conversion_speed_score >= 0) AND (conversion_speed_score <= 100))),
    CONSTRAINT lead_scores_dfa_coverage_type_check CHECK ((dfa_coverage_type = ANY (ARRAY['connected'::text, 'near-net'::text, 'none'::text]))),
    CONSTRAINT lead_scores_product_fit_score_check CHECK (((product_fit_score >= 0) AND (product_fit_score <= 100))),
    CONSTRAINT lead_scores_recommended_track_check CHECK ((recommended_track = ANY (ARRAY['office_park'::text, 'sme_strip'::text, 'clinic'::text, 'referral'::text, 'residential'::text]))),
    CONSTRAINT lead_scores_revenue_potential_score_check CHECK (((revenue_potential_score >= 0) AND (revenue_potential_score <= 100))),
    CONSTRAINT lead_scores_skyfibre_confidence_check CHECK ((skyfibre_confidence = ANY (ARRAY['high'::text, 'medium'::text, 'low'::text, 'none'::text])))
);


