    CONSTRAINT mtn_dealer_product_audit_log_action_check CHECK ((action = ANY (ARRAY['create'::text, 'update'::text, 'delete'::text, 'import'::text, 'status_change'::text, 'price_change'::text])))
);


--
-- Name: mtn_dealer_products; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.mtn_dealer_products (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    deal_id text NOT NULL,
    eppix_package text,
    eppix_tariff text,
    price_plan text NOT NULL,
    package_description text,
    tariff_description text,
    technology text NOT NULL,
    contract_term integer NOT NULL,
    contract_term_label text GENERATED ALWAYS AS (
CASE contract_term
    WHEN 0 THEN 'Month-to-Month'::text
    WHEN 12 THEN '12 Months'::text
    WHEN 24 THEN '24 Months'::text
    WHEN 36 THEN '36 Months'::text
    ELSE NULL::text
END) STORED,
    has_device boolean DEFAULT false NOT NULL,
    device_name text,
    device_status text,
    once_off_pay_in_incl_vat numeric(10,2) DEFAULT 0,
    mtn_price_incl_vat numeric(10,2) NOT NULL,
    mtn_price_excl_vat numeric(10,2) NOT NULL,
    markup_type text DEFAULT 'percentage'::text,
    markup_value numeric(10,2) DEFAULT 0,
    selling_price_excl_vat numeric(10,2) GENERATED ALWAYS AS (
CASE markup_type
    WHEN 'percentage'::text THEN (mtn_price_excl_vat * ((1)::numeric + (markup_value / (100)::numeric)))
    WHEN 'fixed'::text THEN (mtn_price_excl_vat + markup_value)
    ELSE mtn_price_excl_vat
END) STORED,
    selling_price_incl_vat numeric(10,2) GENERATED ALWAYS AS (
CASE markup_type
    WHEN 'percentage'::text THEN ((mtn_price_excl_vat * ((1)::numeric + (markup_value / (100)::numeric))) * 1.15)
    WHEN 'fixed'::text THEN ((mtn_price_excl_vat + markup_value) * 1.15)
    ELSE (mtn_price_excl_vat * 1.15)
END) STORED,
    data_bundle text,
    data_bundle_gb numeric(10,2),
    anytime_minutes text,
    anytime_minutes_value integer,
    on_net_minutes text,
    on_net_minutes_value integer,
    sms_bundle text,
    sms_bundle_value integer,
    inclusive_minutes text,
    inclusive_data text,
    inclusive_sms text,
    inclusive_in_group_calling text,
    inclusive_on_net_minutes text,
    freebies_device text,
    freebies_priceplan text,
    free_sim boolean DEFAULT false,
    free_cli boolean DEFAULT false,
    free_itb boolean DEFAULT false,
    promo_start_date date,
    promo_end_date date,
    channel text DEFAULT 'EBU All'::text,
    available_on_helios boolean DEFAULT false,
    available_on_ilula boolean DEFAULT false,
    commission_tier text GENERATED ALWAYS AS (
CASE
    WHEN (mtn_price_incl_vat < (100)::numeric) THEN 'R0-R99.99'::text
    WHEN (mtn_price_incl_vat < (200)::numeric) THEN 'R100-R199.99'::text
    WHEN (mtn_price_incl_vat < (300)::numeric) THEN 'R200-R299.99'::text
    WHEN (mtn_price_incl_vat < (500)::numeric) THEN 'R300-R499.99'::text
    WHEN (mtn_price_incl_vat < (1000)::numeric) THEN 'R500-R999.99'::text
    WHEN (mtn_price_incl_vat < (2000)::numeric) THEN 'R1000-R1999.99'::text
    ELSE 'R2000+'::text
END) STORED,
    mtn_commission_rate numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (mtn_price_incl_vat < (100)::numeric) THEN 4.75
    WHEN (mtn_price_incl_vat < (200)::numeric) THEN 5.75
    WHEN (mtn_price_incl_vat < (300)::numeric) THEN 7.25
    WHEN (mtn_price_incl_vat < (500)::numeric) THEN 8.75
    WHEN (mtn_price_incl_vat < (1000)::numeric) THEN 9.75
    WHEN (mtn_price_incl_vat < (2000)::numeric) THEN 11.75
    ELSE 13.75
END) STORED,
    circletel_commission_share numeric(5,2) DEFAULT 30.00,
    status text DEFAULT 'active'::text NOT NULL,
    inventory_status text DEFAULT 'Available'::text,
    metadata jsonb DEFAULT '{}'::jsonb,
    import_batch_id text,
    source_file text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    created_by uuid,
    updated_by uuid,
    curation_status text DEFAULT 'uncurated'::text NOT NULL,
    business_use_case text,
    auto_curated boolean DEFAULT false NOT NULL,
    is_visible_on_frontend boolean DEFAULT false NOT NULL,
    total_data text,
    total_minutes text,
    freebie_inventory_status text,
    CONSTRAINT mtn_dealer_products_business_use_case_check CHECK ((business_use_case = ANY (ARRAY['mobile_workforce'::text, 'fleet_management'::text, 'voice_comms'::text, 'data_connectivity'::text, 'iot_m2m'::text, 'device_upgrade'::text, 'backup_connectivity'::text, 'venue_wifi'::text]))),
    CONSTRAINT mtn_dealer_products_contract_term_check CHECK ((contract_term = ANY (ARRAY[0, 12, 24, 36]))),
    CONSTRAINT mtn_dealer_products_curation_status_check CHECK ((curation_status = ANY (ARRAY['uncurated'::text, 'recommended'::text, 'featured'::text, 'hidden'::text]))),
    CONSTRAINT mtn_dealer_products_device_status_check CHECK ((device_status = ANY (ARRAY['Available'::text, 'Out of Stock'::text, 'EOL'::text, 'CTB'::text]))),
    CONSTRAINT mtn_dealer_products_markup_type_check CHECK ((markup_type = ANY (ARRAY['percentage'::text, 'fixed'::text]))),
    CONSTRAINT mtn_dealer_products_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'active'::text, 'inactive'::text, 'archived'::text]))),
    CONSTRAINT mtn_dealer_products_technology_check CHECK ((technology = ANY (ARRAY['LTE'::text, '5G'::text, 'LTE/5G'::text])))
);


