--
-- Name: payment_methods; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.payment_methods (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    customer_id uuid,
    order_id uuid,
    method_type character varying(20) NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    bank_name character varying(100),
    bank_account_name character varying(100),
    bank_account_number_masked character varying(20),
    bank_account_type character varying(20),
    branch_code character varying(10),
    card_type character varying(20),
    card_number_masked character varying(20),
    card_holder_name character varying(100),
    card_expiry_month integer,
    card_expiry_year integer,
    netcash_account_reference character varying(50),
    netcash_mandate_reference character varying(100),
    netcash_mandate_url text,
    netcash_mandate_pdf_link text,
    netcash_token character varying(100),
    mandate_amount numeric(10,2),
    mandate_frequency character varying(20),
    mandate_debit_day integer,
    mandate_agreement_date date,
    mandate_signed_at timestamp with time zone,
    mandate_active boolean DEFAULT false,
    is_primary boolean DEFAULT false,
    is_verified boolean DEFAULT false,
    verification_method character varying(50),
    metadata jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    activated_at timestamp with time zone,
    suspended_at timestamp with time zone,
    cancelled_at timestamp with time zone,
    created_by uuid,
    CONSTRAINT payment_methods_bank_account_type_check CHECK (((bank_account_type)::text = ANY ((ARRAY['current'::character varying, 'savings'::character varying, 'transmission'::character varying])::text[]))),
    CONSTRAINT payment_methods_card_expiry_month_check CHECK (((card_expiry_month >= 1) AND (card_expiry_month <= 12))),
    CONSTRAINT payment_methods_card_expiry_year_check CHECK (((card_expiry_year)::numeric >= EXTRACT(year FROM CURRENT_DATE))),
    CONSTRAINT payment_methods_card_type_check CHECK (((card_type)::text = ANY ((ARRAY['visa'::character varying, 'mastercard'::character varying])::text[]))),
    CONSTRAINT payment_methods_mandate_debit_day_check CHECK ((((mandate_debit_day >= 1) AND (mandate_debit_day <= 31)) OR (mandate_debit_day IS NULL))),
    CONSTRAINT payment_methods_mandate_frequency_check CHECK (((mandate_frequency)::text = ANY ((ARRAY['monthly'::character varying, 'bimonthly'::character varying, 'quarterly'::character varying, 'biannually'::character varying, 'annually'::character varying, 'weekly'::character varying, 'biweekly'::character varying])::text[]))),
    CONSTRAINT payment_methods_method_type_check CHECK (((method_type)::text = ANY ((ARRAY['bank_account'::character varying, 'credit_card'::character varying])::text[]))),
    CONSTRAINT payment_methods_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'active'::character varying, 'suspended'::character varying, 'cancelled'::character varying, 'expired'::character varying, 'failed'::character varying])::text[]))),
    CONSTRAINT valid_bank_account CHECK ((((method_type)::text <> 'bank_account'::text) OR ((bank_name IS NOT NULL) AND (bank_account_name IS NOT NULL) AND (bank_account_number_masked IS NOT NULL)))),
    CONSTRAINT valid_credit_card CHECK ((((method_type)::text <> 'credit_card'::text) OR ((card_type IS NOT NULL) AND (card_number_masked IS NOT NULL) AND (card_holder_name IS NOT NULL) AND (card_expiry_month IS NOT NULL) AND (card_expiry_year IS NOT NULL))))
);


