    provider text NOT NULL,
    amount numeric(10,2) NOT NULL,
    currency text DEFAULT 'ZAR'::text NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    payment_method text,
    payment_method_details jsonb,
    customer_email text,
    customer_name text,
    customer_id uuid,
    invoice_id uuid,
    order_id uuid,
    provider_reference text,
    provider_response jsonb,
    metadata jsonb,
    error_code text,
    error_message text,
    failure_reason text,
    initiated_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    expires_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by uuid,
    zoho_payment_id text,
    zoho_sync_status text DEFAULT 'pending'::text,
    zoho_last_synced_at timestamp with time zone,
    zoho_last_sync_error text,
    customer_invoice_id uuid,
    zoho_books_payment_id text,
    zoho_books_retry_count integer DEFAULT 0,
    zoho_books_next_retry_at timestamp with time zone,
    reconciliation_source character varying(20),
    reconciliation_queue_id uuid,
    CONSTRAINT positive_amount CHECK ((amount > (0)::numeric)),
    CONSTRAINT valid_provider CHECK ((provider = ANY (ARRAY['netcash'::text, 'zoho_billing'::text, 'payfast'::text, 'paygate'::text]))),
    CONSTRAINT valid_status CHECK ((status = ANY (ARRAY['pending'::text, 'processing'::text, 'completed'::text, 'failed'::text, 'refunded'::text, 'cancelled'::text, 'expired'::text])))
);


