    CONSTRAINT valid_commission_model CHECK ((((commission_model = 'tiered_revenue'::text) AND (use_tier_config = true)) OR ((commission_model = 'margin_share'::text) AND (margin_share_rate IS NOT NULL)) OR ((commission_model = 'flat_rate'::text) AND (flat_commission_rate IS NOT NULL)) OR ((commission_model = 'hybrid'::text) AND (base_rate IS NOT NULL) AND (margin_bonus_rate IS NOT NULL))))
);


