    CONSTRAINT product_competitor_matches_match_confidence_check CHECK (((match_confidence >= (0)::numeric) AND (match_confidence <= (1)::numeric))),
    CONSTRAINT product_competitor_matches_match_method_check CHECK ((match_method = ANY (ARRAY['auto'::text, 'manual'::text]))),
    CONSTRAINT product_competitor_matches_product_type_check CHECK ((product_type = ANY (ARRAY['mtn_dealer'::text, 'fibre'::text, 'lte'::text, 'product'::text, 'service_package'::text])))
);


