--
-- Name: product_cost_components; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.product_cost_components (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    package_id uuid NOT NULL,
    name text NOT NULL,
    category public.cost_component_category DEFAULT 'other'::public.cost_component_category NOT NULL,
    cost_amount numeric(10,2) DEFAULT 0 NOT NULL,
    recurrence public.cost_recurrence_type DEFAULT 'monthly'::public.cost_recurrence_type NOT NULL,
    amortisation_months integer,
    amortised_monthly_cost numeric(10,2) GENERATED ALWAYS AS (
CASE
    WHEN ((recurrence = 'amortised'::public.cost_recurrence_type) AND (amortisation_months > 0)) THEN round((cost_amount / (amortisation_months)::numeric), 2)
    WHEN (recurrence = 'annual'::public.cost_recurrence_type) THEN round((cost_amount / (12)::numeric), 2)
    ELSE cost_amount
END) STORED,
    unit_count integer DEFAULT 1,
    supplier_name text,
    supplier_reference text,
    hardware_model text,
    hardware_retail_value numeric(10,2),
    hardware_dealer_cost numeric(10,2),
    description text,
    notes text,
    sort_order integer DEFAULT 0,
    is_optional boolean DEFAULT false,
    is_visible_to_customer boolean DEFAULT false,
    metadata jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    supplier_product_id uuid
);


