--
-- Name: product_price_changes; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.product_price_changes WITH (security_invoker='on') AS
 SELECT pal.id,
    pal.product_id,
    p.name AS product_name,
    p.slug AS product_slug,
    pal.action,
    ((pal.old_values ->> 'base_price_zar'::text))::numeric AS old_monthly_price,
    ((pal.new_values ->> 'base_price_zar'::text))::numeric AS new_monthly_price,
    ((pal.old_values ->> 'cost_price_zar'::text))::numeric AS old_setup_fee,
    ((pal.new_values ->> 'cost_price_zar'::text))::numeric AS new_setup_fee,
        CASE
            WHEN (((pal.new_values ->> 'base_price_zar'::text))::numeric > ((pal.old_values ->> 'base_price_zar'::text))::numeric) THEN 'INCREASE'::text
            WHEN (((pal.new_values ->> 'base_price_zar'::text))::numeric < ((pal.old_values ->> 'base_price_zar'::text))::numeric) THEN 'DECREASE'::text
            ELSE 'NO_CHANGE'::text
        END AS price_trend,
    pal.changed_by_email,
    pal.changed_by_name,
    pal.change_reason,
    pal.changed_at
   FROM (public.product_audit_logs pal
     JOIN public.products p ON ((p.id = pal.product_id)))
  WHERE (('base_price_zar'::text = ANY (pal.changed_fields)) OR ('cost_price_zar'::text = ANY (pal.changed_fields)))
  ORDER BY pal.changed_at DESC;


--
-- Name: VIEW product_price_changes; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.product_price_changes IS 'Simplified view showing only pricing-related changes with trend indicators';


