    wholesale_mrc numeric(10,2) NOT NULL,
    wholesale_nrc numeric(10,2) DEFAULT 0,
    retail_price numeric(10,2) NOT NULL,
    gross_margin_pct numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (retail_price > (0)::numeric) THEN round((((retail_price - wholesale_mrc) / retail_price) * (100)::numeric), 2)
    ELSE (0)::numeric
END) STORED,
    notes text,
    effective_date date DEFAULT CURRENT_DATE NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


