    id uuid DEFAULT gen_random_uuid() NOT NULL,
    provider_name text NOT NULL,
    status text NOT NULL,
    latency_ms integer,
    packet_loss_percent numeric(5,2),
    checked_at timestamp with time zone DEFAULT now() NOT NULL,
    check_source text DEFAULT 'cron'::text,
    details jsonb,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT provider_status_logs_status_check CHECK ((status = ANY (ARRAY['up'::text, 'degraded'::text, 'down'::text, 'maintenance'::text])))
);


--
-- Name: provider_health_current; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.provider_health_current WITH (security_invoker='on') AS
 SELECT DISTINCT ON (provider_status_logs.provider_name) provider_status_logs.provider_name,
    provider_status_logs.status,
    provider_status_logs.latency_ms,
    provider_status_logs.packet_loss_percent,
    provider_status_logs.checked_at,
        CASE
            WHEN (provider_status_logs.status = 'up'::text) THEN 'healthy'::text
            WHEN (provider_status_logs.status = 'degraded'::text) THEN 'warning'::text
            WHEN (provider_status_logs.status = 'maintenance'::text) THEN 'info'::text
            ELSE 'critical'::text
        END AS health_level
   FROM public.provider_status_logs
  ORDER BY provider_status_logs.provider_name, provider_status_logs.checked_at DESC;


