--

CREATE VIEW public.quote_analytics WITH (security_invoker='on') AS
 SELECT q.id AS quote_id,
    q.quote_number,
    q.company_name,
    q.contact_email,
    q.status,
    count(DISTINCT qt.id) FILTER (WHERE (qt.event_type = 'view'::text)) AS total_views,
    count(DISTINCT qt.session_id) FILTER (WHERE (qt.event_type = 'view'::text)) AS unique_views,
    count(DISTINCT qt.id) FILTER (WHERE (qt.event_type = 'email_sent'::text)) AS emails_sent,
    count(DISTINCT qt.id) FILTER (WHERE (qt.event_type = 'shared'::text)) AS shares,
    count(DISTINCT qt.id) FILTER (WHERE (qt.event_type = 'downloaded'::text)) AS downloads,
    max(qt.created_at) FILTER (WHERE (qt.event_type = 'view'::text)) AS last_viewed_at,
    COALESCE(sum(qt.time_spent_seconds) FILTER (WHERE (qt.event_type = 'view'::text)), (0)::bigint) AS total_time_spent_seconds,
    q.created_at AS quote_created_at
   FROM (public.business_quotes q
     LEFT JOIN public.quote_tracking qt ON ((q.id = qt.quote_id)))
  GROUP BY q.id, q.quote_number, q.company_name, q.contact_email, q.status, q.created_at;


