    CONSTRAINT sales_zones_competitor_weakness_score_check CHECK (((competitor_weakness_score >= 0) AND (competitor_weakness_score <= 100))),
    CONSTRAINT sales_zones_coverage_confidence_check CHECK ((coverage_confidence = ANY (ARRAY['high'::text, 'medium'::text, 'low'::text, 'none'::text]))),
    CONSTRAINT sales_zones_priority_check CHECK ((priority = ANY (ARRAY['high'::text, 'medium'::text, 'low'::text]))),
    CONSTRAINT sales_zones_sme_density_score_check CHECK (((sme_density_score >= 0) AND (sme_density_score <= 100))),
    CONSTRAINT sales_zones_status_check CHECK ((status = ANY (ARRAY['active'::text, 'parked'::text, 'saturated'::text]))),
    CONSTRAINT sales_zones_zone_type_check CHECK ((zone_type = ANY (ARRAY['office_park'::text, 'commercial_strip'::text, 'clinic_cluster'::text, 'residential_estate'::text, 'mixed'::text])))
);


