--
-- Name: service_type_mapping; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.service_type_mapping (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    technical_type character varying(50) NOT NULL,
    provider character varying(50) NOT NULL,
    product_category character varying(100) NOT NULL,
    product_name character varying(200),
    priority integer DEFAULT 0,
    active boolean DEFAULT true,
    notes text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT service_type_mapping_product_category_check CHECK (((product_category)::text = ANY ((ARRAY['SkyFibre'::character varying, 'HomeFibreConnect'::character varying, 'BizFibreConnect'::character varying, 'LTE'::character varying, '5G'::character varying, 'wireless'::character varying, 'fibre_consumer'::character varying, 'fibre_business'::character varying, 'lte'::character varying, '5g'::character varying, 'fibre'::character varying, 'connectivity'::character varying])::text[]))),
    CONSTRAINT service_type_mapping_provider_check CHECK (((provider)::text = ANY ((ARRAY['mtn'::character varying, 'dfa'::character varying, 'openserve'::character varying, 'vodacom'::character varying, 'telkom'::character varying, 'cell_c'::character varying])::text[]))),
    CONSTRAINT service_type_mapping_technical_type_check CHECK (((technical_type)::text = ANY ((ARRAY['fibre'::character varying, 'fixed_lte'::character varying, 'uncapped_wireless'::character varying, 'licensed_wireless'::character varying, '5g'::character varying, 'lte'::character varying, '3g_900'::character varying, '3g_2100'::character varying, '2g'::character varying, '5G'::character varying, 'LTE'::character varying, 'FixedLTE'::character varying, 'Fixed Wireless Broadband'::character varying, 'Wholesale FTTH FNO'::character varying, 'Wholesale FTTH (MNS)'::character varying, 'Wholesale Cloud Connect'::character varying, 'Wholesale Access Connect'::character varying, 'Wholesale Ethernet Wave Leased Line'::character varying, 'Wholesale Cloud Connect Lite'::character varying])::text[])))
);


--
-- Name: TABLE service_type_mapping; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.service_type_mapping IS 'Maps technical service types from provider APIs to CircleTel product categories.

Coverage Check Flow:
1. MTN API returns: uncapped_wireless, 5G, LTE, Fixed Wireless Broadband
2. This table maps technical types to product categories
3. Packages API queries service_packages by product_category

Key Mappings for SkyFibre:
- uncapped_wireless → connectivity (SkyFibre Home/SME products)
- uncapped_wireless → wireless (legacy mapping, kept for compatibility)
- Fixed Wireless Broadband → connectivity (MTN Wholesale mapping)

Customer Type Mapping:
- SkyFibre Home* → consumer (residential packages page)
- SkyFibre SME* → business (business packages page)';


--
-- Name: COLUMN service_type_mapping.technical_type; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.service_type_mapping.technical_type IS 'Technical service type from coverage API (e.g., uncapped_wireless, fibre, 5g)';


--
-- Name: COLUMN service_type_mapping.provider; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.service_type_mapping.provider IS 'Coverage provider (mtn, dfa, openserve, etc.)';


--
-- Name: COLUMN service_type_mapping.product_category; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.service_type_mapping.product_category IS 'CircleTel product category (SkyFibre, HomeFibreConnect, BizFibreConnect, LTE, 5G)';


--
-- Name: COLUMN service_type_mapping.priority; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.service_type_mapping.priority IS 'Priority for product selection when multiple services available (lower = higher priority)';


