--
-- Name: smb_products_complete; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.smb_products_complete AS
SELECT
    NULL::uuid AS id,
    NULL::character varying(255) AS package_name,
    NULL::character varying(50) AS package_code,
    NULL::integer AS speed_mbps,
    NULL::character varying(50) AS product_category,
    NULL::numeric(10,2) AS regular_price_zar,
    NULL::numeric(10,2) AS promo_price_zar,
    NULL::numeric(10,2) AS installation_fee_zar,
    NULL::numeric(10,2) AS total_first_month_regular_zar,
    NULL::numeric(10,2) AS total_first_month_promo_zar,
    NULL::numeric(10,2) AS selling_price_excl_vat_zar,
    NULL::numeric(10,2) AS selling_price_incl_vat_zar,
    NULL::numeric(10,2) AS total_cost_zar,
    NULL::numeric(10,2) AS gross_profit_zar,
    NULL::numeric(5,2) AS gross_margin_percentage,
    NULL::character varying(255) AS router_model,
    NULL::numeric(10,2) AS router_retail_price_incl_vat_zar,
    NULL::numeric(10,2) AS router_dealer_price_excl_vat_zar,
    NULL::numeric(10,2) AS router_amortised_monthly_zar,
    NULL::character varying(50) AS router_wifi_standard,
    NULL::integer AS router_ports,
    NULL::integer AS router_concurrent_users,
    NULL::integer AS router_throughput_mbps,
    NULL::jsonb AS router_features,
    NULL::boolean AS is_active,
    NULL::date AS effective_date,
    NULL::character varying(20) AS version,
    NULL::timestamp with time zone AS created_at,
    NULL::timestamp with time zone AS updated_at,
    NULL::json AS cost_components,
    NULL::json AS features;


--
-- Name: sme_packages; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.sme_packages WITH (security_invoker='on') AS
 SELECT service_packages.id,
    service_packages.name,
    service_packages.service_type,
    service_packages.speed_down,
    service_packages.speed_up,
    service_packages.price,
    service_packages.promotion_price,
    service_packages.description,
    service_packages.features,
    service_packages.customer_type,
    service_packages.product_category,
    service_packages.active,
    service_packages.created_at
   FROM public.service_packages
  WHERE (((service_packages.name)::text ~~ '%SME%'::text) AND ((service_packages.customer_type)::text = 'business'::text) AND ((service_packages.product_category)::text = 'wireless'::text) AND (service_packages.active = true))
  ORDER BY service_packages.price;


--
-- Name: VIEW sme_packages; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.sme_packages IS 'SME SkyFibre wireless packages for small to medium businesses (5-50 employees)';


