 SELECT aal.id,
    aal.user_email,
    au.full_name,
    aal.action,
    aal.action_category,
    aal.status,
    aal.severity,
    aal.is_suspicious,
    aal.ip_address,
    aal.created_at,
    aal.metadata
   FROM (public.admin_audit_logs aal
     LEFT JOIN public.admin_users au ON ((au.id = aal.admin_user_id)))
  WHERE (aal.created_at > (now() - '30 days'::interval))
  ORDER BY aal.created_at DESC;


--
-- Name: v_ar_dashboard_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ar_dashboard_summary WITH (security_invoker='on') AS
 SELECT count(*) FILTER (WHERE ((ci.status)::text = ANY ((ARRAY['unpaid'::character varying, 'overdue'::character varying, 'partial'::character varying])::text[]))) AS total_outstanding_invoices,
    COALESCE(sum(ci.amount_due) FILTER (WHERE ((ci.status)::text = ANY ((ARRAY['unpaid'::character varying, 'overdue'::character varying, 'partial'::character varying])::text[]))), (0)::numeric) AS total_outstanding_amount,
    count(*) FILTER (WHERE (ci.due_date >= CURRENT_DATE)) AS current_count,
    COALESCE(sum(ci.amount_due) FILTER (WHERE (ci.due_date >= CURRENT_DATE)), (0)::numeric) AS current_amount,
    count(*) FILTER (WHERE ((ci.due_date < CURRENT_DATE) AND (ci.due_date >= (CURRENT_DATE - '30 days'::interval)))) AS overdue_1_30_count,
    COALESCE(sum(ci.amount_due) FILTER (WHERE ((ci.due_date < CURRENT_DATE) AND (ci.due_date >= (CURRENT_DATE - '30 days'::interval)))), (0)::numeric) AS overdue_1_30_amount,
    count(*) FILTER (WHERE ((ci.due_date < (CURRENT_DATE - '30 days'::interval)) AND (ci.due_date >= (CURRENT_DATE - '60 days'::interval)))) AS overdue_31_60_count,
    COALESCE(sum(ci.amount_due) FILTER (WHERE ((ci.due_date < (CURRENT_DATE - '30 days'::interval)) AND (ci.due_date >= (CURRENT_DATE - '60 days'::interval)))), (0)::numeric) AS overdue_31_60_amount,
    count(*) FILTER (WHERE ((ci.due_date < (CURRENT_DATE - '60 days'::interval)) AND (ci.due_date >= (CURRENT_DATE - '90 days'::interval)))) AS overdue_61_90_count,
    COALESCE(sum(ci.amount_due) FILTER (WHERE ((ci.due_date < (CURRENT_DATE - '60 days'::interval)) AND (ci.due_date >= (CURRENT_DATE - '90 days'::interval)))), (0)::numeric) AS overdue_61_90_amount,
    count(*) FILTER (WHERE (ci.due_date < (CURRENT_DATE - '90 days'::interval))) AS overdue_90_plus_count,
    COALESCE(sum(ci.amount_due) FILTER (WHERE (ci.due_date < (CURRENT_DATE - '90 days'::interval))), (0)::numeric) AS overdue_90_plus_amount,
    COALESCE(avg((CURRENT_DATE - ci.due_date)) FILTER (WHERE ((ci.due_date < CURRENT_DATE) AND ((ci.status)::text = ANY ((ARRAY['unpaid'::character varying, 'overdue'::character varying, 'partial'::character varying])::text[])))), (0)::numeric) AS avg_days_overdue
   FROM public.customer_invoices ci
  WHERE ((ci.status)::text = ANY ((ARRAY['unpaid'::character varying, 'overdue'::character varying, 'partial'::character varying, 'sent'::character varying])::text[]));


--
-- Name: VIEW v_ar_dashboard_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_ar_dashboard_summary IS 'Real-time AR dashboard summary';


--
-- Name: v_competitor_price_comparison; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_competitor_price_comparison WITH (security_invoker='on') AS
 SELECT pcm.id AS match_id,
    pcm.product_type,
    pcm.product_id,
    pcm.match_confidence,
    pcm.match_method,
    cp.id AS competitor_product_id,
    cp.provider_id,
    prov.name AS competitor_name,
    prov.slug AS competitor_slug,
    prov.logo_url AS competitor_logo,
    cp.product_name AS competitor_product,
    cp.monthly_price AS competitor_price,
    cp.once_off_price AS competitor_once_off,
    cp.data_bundle AS competitor_data,
    cp.data_gb AS competitor_data_gb,
    cp.contract_term AS competitor_term,
    cp.technology AS competitor_technology,
    cp.device_name AS competitor_device,
    cp.scraped_at,
    cp.source_url
   FROM ((public.product_competitor_matches pcm
     JOIN public.competitor_products cp ON ((pcm.competitor_product_id = cp.id)))
     JOIN public.competitor_providers prov ON ((cp.provider_id = prov.id)))
  WHERE (cp.is_current = true);


--
-- Name: VIEW v_competitor_price_comparison; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_competitor_price_comparison IS 'Denormalized view for easy price comparison queries';


