--
-- Name: v_customer_notification_engagement; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_customer_notification_engagement WITH (security_invoker='on') AS
 SELECT c.id AS customer_id,
    c.email,
    c.phone,
    count(DISTINCT nt.message_id) AS total_notifications,
    count(DISTINCT nt.message_id) FILTER (WHERE (nt.notification_type = 'email'::text)) AS total_emails,
    count(DISTINCT nt.message_id) FILTER (WHERE (nt.notification_type = 'sms'::text)) AS total_sms,
    count(nt.id) FILTER (WHERE (nt.event_type = 'opened'::text)) AS email_opens,
    count(nt.id) FILTER (WHERE (nt.event_type = 'clicked'::text)) AS link_clicks,
        CASE
            WHEN (count(DISTINCT nt.message_id) FILTER (WHERE (nt.notification_type = 'email'::text)) > 0) THEN (((count(nt.id) FILTER (WHERE (nt.event_type = 'opened'::text)))::numeric / (count(DISTINCT nt.message_id) FILTER (WHERE (nt.notification_type = 'email'::text)))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS engagement_score,
    max(nt."timestamp") AS last_notification,
    max(nt."timestamp") FILTER (WHERE (nt.event_type = 'opened'::text)) AS last_opened_email,
    max(nt."timestamp") FILTER (WHERE (nt.event_type = 'clicked'::text)) AS last_clicked_link
   FROM (public.customers c
     LEFT JOIN public.notification_tracking nt ON ((c.id = nt.customer_id)))
  GROUP BY c.id, c.email, c.phone;


--
-- Name: VIEW v_customer_notification_engagement; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_customer_notification_engagement IS 'Customer notification engagement metrics';


--
-- Name: v_email_template_performance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_email_template_performance WITH (security_invoker='on') AS
 SELECT et.template_id,
    et.name,
    et.category,
    et.send_count AS total_sent,
    et.last_sent_at,
    count(etv.id) AS version_count,
    count(etv.id) FILTER (WHERE (etv.is_active = true)) AS active_versions,
    avg(etv.open_rate) AS avg_open_rate,
    avg(etv.click_rate) AS avg_click_rate
   FROM (public.email_templates et
     LEFT JOIN public.email_template_versions etv ON ((et.template_id = etv.template_id)))
  GROUP BY et.template_id, et.name, et.category, et.send_count, et.last_sent_at;


--
-- Name: VIEW v_email_template_performance; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_email_template_performance IS 'Email template performance metrics and A/B test results';


--
-- Name: v_marketing_email_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_marketing_email_status WITH (security_invoker='on') AS
 SELECT marketing_email_preferences.email,
    marketing_email_preferences.customer_id,
        CASE
            WHEN marketing_email_preferences.unsubscribed_all THEN false
            ELSE marketing_email_preferences.promotional_emails
        END AS can_receive_promotional,
        CASE
            WHEN marketing_email_preferences.unsubscribed_all THEN false
            ELSE marketing_email_preferences.newsletter_emails
        END AS can_receive_newsletter,
        CASE
            WHEN marketing_email_preferences.unsubscribed_all THEN false
            ELSE marketing_email_preferences.product_updates
        END AS can_receive_product_updates,
        CASE
            WHEN marketing_email_preferences.unsubscribed_all THEN false
            ELSE marketing_email_preferences.partner_offers
        END AS can_receive_partner_offers,
    (NOT marketing_email_preferences.unsubscribed_all) AS can_receive_any_marketing,
    marketing_email_preferences.unsubscribed_at,
    marketing_email_preferences.updated_at
   FROM public.marketing_email_preferences;


--
-- Name: VIEW v_marketing_email_status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_marketing_email_status IS 'View to easily check if an email address should receive marketing communications';


--
-- Name: v_mtn_curated_deals; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_mtn_curated_deals WITH (security_invoker='on') AS
 SELECT p.id,
    p.deal_id,
    p.price_plan,
    p.package_description,
    p.tariff_description,
    p.technology,
    p.contract_term,
    p.contract_term_label,
    p.has_device,
    p.device_name,
    p.device_status,
    p.once_off_pay_in_incl_vat,
    p.mtn_price_incl_vat,
    p.mtn_price_excl_vat,
    p.markup_type,
    p.markup_value,
    p.selling_price_excl_vat,
    p.selling_price_incl_vat,
    p.commission_tier,
    p.mtn_commission_rate,
    p.circletel_commission_share,
    (((p.mtn_price_incl_vat * (p.contract_term)::numeric) * p.mtn_commission_rate) / (100)::numeric) AS mtn_commission_to_arlan,
    (((((p.mtn_price_incl_vat * (p.contract_term)::numeric) * p.mtn_commission_rate) / (100)::numeric) * p.circletel_commission_share) / (100)::numeric) AS circletel_commission,
    ((p.mtn_commission_rate * p.circletel_commission_share) / (100)::numeric) AS effective_commission_rate,
        CASE p.markup_type
            WHEN 'percentage'::text THEN (p.mtn_price_excl_vat * (p.markup_value / (100)::numeric))
            WHEN 'fixed'::text THEN p.markup_value
            ELSE (0)::numeric
        END AS monthly_markup_revenue,
    p.data_bundle,
    p.data_bundle_gb,
    p.anytime_minutes,
    p.anytime_minutes_value,
    p.on_net_minutes,
    p.sms_bundle,
    p.total_data,
    p.total_minutes,
    p.freebies_device,
    p.freebies_priceplan,
    p.free_sim,
    p.free_cli,
    p.free_itb,
    p.curation_status,
    p.business_use_case,
    p.auto_curated,
    p.is_visible_on_frontend,
    p.promo_start_date,
    p.promo_end_date,
    ((p.promo_start_date <= CURRENT_DATE) AND ((p.promo_end_date IS NULL) OR (p.promo_end_date >= CURRENT_DATE))) AS is_current_deal,
    p.channel,
    p.available_on_helios,
    p.available_on_ilula,
    p.status,
    p.inventory_status
   FROM public.mtn_dealer_products p
  WHERE ((p.status = 'active'::text) AND (p.curation_status = ANY (ARRAY['recommended'::text, 'featured'::text])));


--
-- Name: v_mtn_dealer_commission_calculator; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_mtn_dealer_commission_calculator WITH (security_invoker='on') AS
 SELECT mtn_dealer_products.id,
    mtn_dealer_products.deal_id,
    mtn_dealer_products.price_plan,
    mtn_dealer_products.device_name,
    mtn_dealer_products.technology,
    mtn_dealer_products.contract_term,
    mtn_dealer_products.contract_term_label,
    mtn_dealer_products.has_device,
    mtn_dealer_products.mtn_price_incl_vat,
    mtn_dealer_products.mtn_price_excl_vat,
    mtn_dealer_products.markup_type,
    mtn_dealer_products.markup_value,
    mtn_dealer_products.selling_price_excl_vat,
    mtn_dealer_products.selling_price_incl_vat,
    mtn_dealer_products.commission_tier,
    mtn_dealer_products.mtn_commission_rate,
    mtn_dealer_products.circletel_commission_share,
    (mtn_dealer_products.mtn_price_incl_vat * (mtn_dealer_products.contract_term)::numeric) AS total_contract_value,
    (((mtn_dealer_products.mtn_price_incl_vat * (mtn_dealer_products.contract_term)::numeric) * mtn_dealer_products.mtn_commission_rate) / (100)::numeric) AS mtn_commission_to_arlan,
    (((((mtn_dealer_products.mtn_price_incl_vat * (mtn_dealer_products.contract_term)::numeric) * mtn_dealer_products.mtn_commission_rate) / (100)::numeric) * mtn_dealer_products.circletel_commission_share) / (100)::numeric) AS circletel_commission,
    ((((((mtn_dealer_products.mtn_price_incl_vat * (mtn_dealer_products.contract_term)::numeric) * mtn_dealer_products.mtn_commission_rate) / (100)::numeric) * mtn_dealer_products.circletel_commission_share) / (100)::numeric) * 1.15) AS circletel_commission_incl_vat,
    ((mtn_dealer_products.mtn_commission_rate * mtn_dealer_products.circletel_commission_share) / (100)::numeric) AS effective_commission_rate,
    mtn_dealer_products.data_bundle,
    mtn_dealer_products.anytime_minutes,
    mtn_dealer_products.sms_bundle,
    mtn_dealer_products.status,
    mtn_dealer_products.promo_start_date,
    mtn_dealer_products.promo_end_date,
    ((mtn_dealer_products.promo_start_date <= CURRENT_DATE) AND ((mtn_dealer_products.promo_end_date IS NULL) OR (mtn_dealer_products.promo_end_date >= CURRENT_DATE))) AS is_current_deal
   FROM public.mtn_dealer_products
  WHERE (mtn_dealer_products.status = 'active'::text);


--
-- Name: VIEW v_mtn_dealer_commission_calculator; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_mtn_dealer_commission_calculator IS 'Pre-calculated commission values for all active MTN dealer products';


--
-- Name: v_mtn_dealer_deal_periods; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_mtn_dealer_deal_periods WITH (security_invoker='on') AS
 SELECT mtn_dealer_products.promo_start_date,
    mtn_dealer_products.promo_end_date,
    count(*) AS deal_count,
    count(*) FILTER (WHERE ((mtn_dealer_products.promo_start_date <= CURRENT_DATE) AND ((mtn_dealer_products.promo_end_date IS NULL) OR (mtn_dealer_products.promo_end_date >= CURRENT_DATE)))) AS active_deals,
    count(*) FILTER (WHERE mtn_dealer_products.has_device) AS deals_with_device,
    count(*) FILTER (WHERE (NOT mtn_dealer_products.has_device)) AS sim_only_deals,
    min(mtn_dealer_products.mtn_price_incl_vat) AS min_price,
    max(mtn_dealer_products.mtn_price_incl_vat) AS max_price
   FROM public.mtn_dealer_products
  WHERE (mtn_dealer_products.status = 'active'::text)
  GROUP BY mtn_dealer_products.promo_start_date, mtn_dealer_products.promo_end_date
  ORDER BY mtn_dealer_products.promo_start_date DESC;


--
-- Name: v_mtn_dealer_product_categories; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_mtn_dealer_product_categories WITH (security_invoker='on') AS
 SELECT DISTINCT mtn_dealer_products.technology,
    mtn_dealer_products.contract_term,
    mtn_dealer_products.contract_term_label,
    mtn_dealer_products.has_device,
        CASE
            WHEN mtn_dealer_products.has_device THEN 'With Device'::text
            ELSE 'SIM Only'::text
        END AS device_category,
    mtn_dealer_products.commission_tier,
    count(*) AS product_count,
    min(mtn_dealer_products.mtn_price_incl_vat) AS min_price,
    max(mtn_dealer_products.mtn_price_incl_vat) AS max_price,
    avg(mtn_dealer_products.mtn_price_incl_vat) AS avg_price
   FROM public.mtn_dealer_products
  WHERE (mtn_dealer_products.status = 'active'::text)
  GROUP BY mtn_dealer_products.technology, mtn_dealer_products.contract_term, mtn_dealer_products.contract_term_label, mtn_dealer_products.has_device, mtn_dealer_products.commission_tier
  ORDER BY mtn_dealer_products.technology, mtn_dealer_products.contract_term, mtn_dealer_products.has_device;


--
-- Name: v_notification_analytics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_notification_analytics WITH (security_invoker='on') AS
 SELECT (date_trunc('day'::text, invoice_notification_log.created_at))::date AS date,
    invoice_notification_log.notification_type,
    count(*) AS total_sent,
    count(*) FILTER (WHERE (invoice_notification_log.status = 'delivered'::text)) AS delivered,
    count(*) FILTER (WHERE (invoice_notification_log.status = 'opened'::text)) AS opened,
    count(*) FILTER (WHERE (invoice_notification_log.status = 'clicked'::text)) AS clicked,
    count(*) FILTER (WHERE (invoice_notification_log.status = 'failed'::text)) AS failed,
    sum(invoice_notification_log.amount_due) AS total_amount_notified,
    avg(invoice_notification_log.days_overdue) AS avg_days_overdue
   FROM public.invoice_notification_log
  GROUP BY ((date_trunc('day'::text, invoice_notification_log.created_at))::date), invoice_notification_log.notification_type
  ORDER BY ((date_trunc('day'::text, invoice_notification_log.created_at))::date) DESC;


--
-- Name: VIEW v_notification_analytics; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_notification_analytics IS 'Notification analytics by day and type';


--
-- Name: v_order_compliance_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_order_compliance_summary WITH (security_invoker='on') AS
 SELECT co.id AS order_id,
    co.order_number,
    ((co.first_name || ' '::text) || co.last_name) AS customer_name,
    co.email,
    count(*) FILTER (WHERE ((cd.category = 'fica'::text) AND (cd.status = 'pending'::text))) AS fica_pending,
    count(*) FILTER (WHERE ((cd.category = 'fica'::text) AND (cd.status = 'approved'::text))) AS fica_approved,
    count(*) FILTER (WHERE ((cd.category = 'fica'::text) AND (cd.status = 'rejected'::text))) AS fica_rejected,
    count(*) FILTER (WHERE ((cd.category = 'rica'::text) AND (cd.status = 'pending'::text))) AS rica_pending,
    count(*) FILTER (WHERE ((cd.category = 'rica'::text) AND (cd.status = 'approved'::text))) AS rica_approved,
    count(*) FILTER (WHERE ((cd.category = 'rica'::text) AND (cd.status = 'rejected'::text))) AS rica_rejected,
        CASE
            WHEN (count(*) FILTER (WHERE (cd.status = 'rejected'::text)) > 0) THEN 'rejected'::text
            WHEN (count(*) FILTER (WHERE (cd.status = 'pending'::text)) > 0) THEN 'pending'::text
            WHEN (count(*) FILTER (WHERE (cd.status = 'approved'::text)) >= 4) THEN 'complete'::text
            ELSE 'incomplete'::text
        END AS compliance_status,
    min(cd.uploaded_at) AS first_upload,
    max(cd.reviewed_at) AS last_review
   FROM (public.consumer_orders co
     LEFT JOIN public.compliance_documents cd ON ((co.id = cd.order_id)))
  GROUP BY co.id, co.order_number, co.first_name, co.last_name, co.email;


--
-- Name: VIEW v_order_compliance_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_order_compliance_summary IS 'Summary of compliance document status per order';


--
-- Name: v_order_notifications; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_order_notifications WITH (security_invoker='on') AS
 SELECT co.id AS order_id,
    co.order_number,
    ((co.first_name || ' '::text) || co.last_name) AS customer_name,
    co.email,
    co.phone,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'sent'::text) AND (nt.notification_type = 'email'::text))) AS emails_sent,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'email'::text))) AS emails_delivered,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'opened'::text) AND (nt.notification_type = 'email'::text))) AS emails_opened,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'clicked'::text) AND (nt.notification_type = 'email'::text))) AS emails_clicked,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'bounced'::text) AND (nt.notification_type = 'email'::text))) AS emails_bounced,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'sent'::text) AND (nt.notification_type = 'sms'::text))) AS sms_sent,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'sms'::text))) AS sms_delivered,
    count(nt.id) FILTER (WHERE ((nt.event_type = 'failed'::text) AND (nt.notification_type = 'sms'::text))) AS sms_failed,
        CASE
            WHEN (count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'email'::text))) > 0) THEN (((count(nt.id) FILTER (WHERE ((nt.event_type = 'opened'::text) AND (nt.notification_type = 'email'::text))))::numeric / (count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'email'::text))))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS email_open_rate,
        CASE
            WHEN (count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'email'::text))) > 0) THEN (((count(nt.id) FILTER (WHERE ((nt.event_type = 'clicked'::text) AND (nt.notification_type = 'email'::text))))::numeric / (count(nt.id) FILTER (WHERE ((nt.event_type = 'delivered'::text) AND (nt.notification_type = 'email'::text))))::numeric) * (100)::numeric)
            ELSE (0)::numeric
        END AS email_click_rate,
    max(nt."timestamp") FILTER (WHERE ((nt.event_type = 'sent'::text) AND (nt.notification_type = 'email'::text))) AS last_email_sent,
    max(nt."timestamp") FILTER (WHERE (nt.event_type = 'opened'::text)) AS last_email_opened,
    max(nt."timestamp") FILTER (WHERE (nt.event_type = 'clicked'::text)) AS last_link_clicked,
    max(nt."timestamp") AS last_notification_event
   FROM (public.consumer_orders co
     LEFT JOIN public.notification_tracking nt ON ((co.id = nt.order_id)))
  GROUP BY co.id, co.order_number, co.first_name, co.last_name, co.email, co.phone;


--
-- Name: VIEW v_order_notifications; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_order_notifications IS 'Summary of notification tracking metrics per order';


--
-- Name: v_partner_commission_tier_analysis; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_partner_commission_tier_analysis WITH (security_invoker='on') AS
 SELECT p.id AS partner_id,
    p.business_name,
    p.tier AS partner_tier,
    p.commission_rate AS partner_default_rate,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 1)) AS tier1_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 2)) AS tier2_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 3)) AS tier3_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 4)) AS tier4_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 5)) AS tier5_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 6)) AS tier6_transactions,
    count(DISTINCT pct.id) FILTER (WHERE (ct.tier_order = 7)) AS tier7_transactions,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 1)), (0)::numeric) AS tier1_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 2)), (0)::numeric) AS tier2_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 3)), (0)::numeric) AS tier3_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 4)), (0)::numeric) AS tier4_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 5)), (0)::numeric) AS tier5_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 6)), (0)::numeric) AS tier6_commission,
    COALESCE(sum(pct.amount) FILTER (WHERE (ct.tier_order = 7)), (0)::numeric) AS tier7_commission,
    count(DISTINCT pct.id) AS total_transactions,
    COALESCE(sum(pct.amount), (0)::numeric) AS total_commission,
    avg(pct.monthly_subscription_value) AS avg_monthly_subscription,
    avg(pct.amount) AS avg_commission_per_deal
   FROM ((public.partners p
     LEFT JOIN public.partner_commission_transactions pct ON ((p.id = pct.partner_id)))
     LEFT JOIN public.commission_tier_config ct ON ((pct.commission_tier_id = ct.id)))
  WHERE (p.status = 'approved'::text)
  GROUP BY p.id, p.business_name, p.tier, p.commission_rate;


--
-- Name: VIEW v_partner_commission_tier_analysis; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_partner_commission_tier_analysis IS 'Partner performance analysis showing transaction counts and revenue by commission tier';


--
-- Name: v_payment_provider_health; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_payment_provider_health WITH (security_invoker='on') AS
 SELECT pps.provider,
    pps.enabled,
    pps.priority,
    pps.test_mode,
    count(pt.id) AS total_transactions,
    sum(
        CASE
            WHEN (pt.status = 'completed'::text) THEN 1
            ELSE 0
        END) AS completed_transactions,
    sum(
        CASE
            WHEN (pt.status = 'failed'::text) THEN 1
            ELSE 0
        END) AS failed_transactions,
    sum(
        CASE
            WHEN (pt.status = 'completed'::text) THEN pt.amount
            ELSE (0)::numeric
        END) AS total_amount,
    avg(
        CASE
            WHEN (pt.status = 'completed'::text) THEN EXTRACT(epoch FROM (pt.completed_at - pt.initiated_at))
            ELSE NULL::numeric
        END) AS avg_completion_time_seconds
   FROM (public.payment_provider_settings pps
     LEFT JOIN public.payment_transactions pt ON (((pps.provider = pt.provider) AND (pt.created_at > (now() - '30 days'::interval)))))
  GROUP BY pps.provider, pps.enabled, pps.priority, pps.test_mode;


--
-- Name: v_pending_compliance_reviews; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_pending_compliance_reviews WITH (security_invoker='on') AS
 SELECT cd.id,
    cd.order_id,
    co.order_number,
    ((co.first_name || ' '::text) || co.last_name) AS customer_name,
    co.email,
    cd.category,
    cd.document_type,
    cd.file_name,
    cd.file_url,
    cd.uploaded_at,
    (EXTRACT(epoch FROM (now() - cd.uploaded_at)) / (3600)::numeric) AS hours_pending
   FROM (public.compliance_documents cd
     JOIN public.consumer_orders co ON ((cd.order_id = co.id)))
  WHERE (cd.status = 'pending'::text)
  ORDER BY cd.uploaded_at;


--
-- Name: VIEW v_pending_compliance_reviews; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_pending_compliance_reviews IS 'Documents pending compliance review';


--
-- Name: v_product_commission_comparison; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_product_commission_comparison WITH (security_invoker='on') AS
 SELECT product_commission_config.product_line,
    product_commission_config.product_name,
    product_commission_config.commission_model,
    product_commission_config.monthly_price,
    product_commission_config.monthly_cost,
    product_commission_config.monthly_margin,
    product_commission_config.margin_percentage,
        CASE
            WHEN (product_commission_config.commission_model = 'margin_share'::text) THEN product_commission_config.margin_share_rate
            WHEN (product_commission_config.commission_model = 'flat_rate'::text) THEN product_commission_config.flat_commission_rate
            WHEN (product_commission_config.commission_model = 'tiered_revenue'::text) THEN NULL::numeric
            ELSE NULL::numeric
        END AS commission_rate,
        CASE
            WHEN (product_commission_config.commission_model = 'margin_share'::text) THEN (((product_commission_config.monthly_margin * product_commission_config.margin_share_rate) / (100)::numeric) * (24)::numeric)
            WHEN (product_commission_config.commission_model = 'flat_rate'::text) THEN (((product_commission_config.monthly_price * product_commission_config.flat_commission_rate) / (100)::numeric) * (24)::numeric)
            WHEN (product_commission_config.commission_model = 'tiered_revenue'::text) THEN NULL::numeric
            ELSE NULL::numeric
        END AS commission_24_months,
        CASE
            WHEN (product_commission_config.commission_model = 'margin_share'::text) THEN ((product_commission_config.monthly_margin * product_commission_config.margin_share_rate) / (100)::numeric)
            WHEN (product_commission_config.commission_model = 'flat_rate'::text) THEN ((product_commission_config.monthly_price * product_commission_config.flat_commission_rate) / (100)::numeric)
            ELSE NULL::numeric
        END AS commission_per_month,
    product_commission_config.is_active,
    product_commission_config.sort_order
   FROM public.product_commission_config
  WHERE (product_commission_config.is_active = true)
  ORDER BY product_commission_config.product_line, product_commission_config.sort_order;


--
-- Name: VIEW v_product_commission_comparison; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_product_commission_comparison IS 'Side-by-side comparison of commission earnings across all product lines';


--
-- Name: v_product_cost_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_product_cost_summary WITH (security_invoker='on') AS
 SELECT product_cost_components.package_id,
    count(*) AS component_count,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
            ELSE (0)::numeric
        END) AS direct_monthly_cost,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = 'amortised'::public.cost_recurrence_type) THEN product_cost_components.amortised_monthly_cost
            ELSE (0)::numeric
        END) AS amortised_monthly_cost,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = 'annual'::public.cost_recurrence_type) THEN product_cost_components.amortised_monthly_cost
            ELSE (0)::numeric
        END) AS annual_monthly_cost,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = ANY (ARRAY['per_user'::public.cost_recurrence_type, 'per_device'::public.cost_recurrence_type])) THEN (product_cost_components.cost_amount * (product_cost_components.unit_count)::numeric)
            ELSE (0)::numeric
        END) AS unit_monthly_cost,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
            WHEN (product_cost_components.recurrence = ANY (ARRAY['amortised'::public.cost_recurrence_type, 'annual'::public.cost_recurrence_type])) THEN product_cost_components.amortised_monthly_cost
            WHEN (product_cost_components.recurrence = ANY (ARRAY['per_user'::public.cost_recurrence_type, 'per_device'::public.cost_recurrence_type])) THEN (product_cost_components.cost_amount * (product_cost_components.unit_count)::numeric)
            ELSE (0)::numeric
        END) AS total_monthly_cost,
    sum(
        CASE
            WHEN (product_cost_components.recurrence = 'once_off'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
            ELSE (0)::numeric
        END) AS total_once_off_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'hardware'::public.cost_component_category) THEN product_cost_components.hardware_retail_value
            ELSE (0)::numeric
        END) AS total_hardware_retail,
    sum(
        CASE
            WHEN (product_cost_components.category = 'hardware'::public.cost_component_category) THEN product_cost_components.hardware_dealer_cost
            ELSE (0)::numeric
        END) AS total_hardware_dealer,
    sum(
        CASE
            WHEN (product_cost_components.category = 'provider'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS provider_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'infrastructure'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS infrastructure_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'platform'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS platform_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'hardware'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS hardware_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'addon_service'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS addon_service_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'support'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS support_cost,
    sum(
        CASE
            WHEN (product_cost_components.category = 'installation'::public.cost_component_category) THEN
            CASE
                WHEN (product_cost_components.recurrence = 'monthly'::public.cost_recurrence_type) THEN product_cost_components.cost_amount
                ELSE product_cost_components.amortised_monthly_cost
            END
            ELSE (0)::numeric
        END) AS installation_cost
   FROM public.product_cost_components
  GROUP BY product_cost_components.package_id;


--
-- Name: VIEW v_product_cost_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_product_cost_summary IS 'Aggregated cost summary per product for margin calculations';


--
-- Name: v_products_with_providers; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_products_with_providers WITH (security_invoker='on') AS
 SELECT sp.id,
    sp.name,
    sp.service_type,
    sp.product_category,
    sp.customer_type,
    sp.speed_down,
    sp.speed_up,
    sp.price,
    sp.compatible_providers,
    sp.active,
    ( SELECT json_agg(ordered_providers.provider_info ORDER BY (ordered_providers.provider_info ->> 'priority'::text)) AS json_agg
           FROM ( SELECT json_build_object('provider_code', fnp.provider_code, 'provider_name', fnp.display_name, 'logo_url', fnp.logo_url, 'logo_dark_url', fnp.logo_dark_url, 'logo_light_url', fnp.logo_light_url, 'logo_format', fnp.logo_format, 'logo_aspect_ratio', fnp.logo_aspect_ratio, 'active', fnp.active, 'priority', fnp.priority) AS provider_info
                   FROM public.fttb_network_providers fnp
                  WHERE (fnp.provider_code = ANY (sp.compatible_providers))
                  ORDER BY fnp.priority) ordered_providers) AS provider_details
   FROM public.service_packages sp
  WHERE ((sp.active = true) AND (sp.compatible_providers IS NOT NULL) AND (array_length(sp.compatible_providers, 1) > 0));


--
-- Name: v_providers_with_logos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_providers_with_logos WITH (security_invoker='on') AS
 SELECT fttb_network_providers.id,
    fttb_network_providers.name,
    fttb_network_providers.display_name,
    fttb_network_providers.provider_code,
    fttb_network_providers.provider_type,
    fttb_network_providers.service_offerings,
    fttb_network_providers.coverage_source,
    fttb_network_providers.priority,
    fttb_network_providers.logo_url,
    fttb_network_providers.logo_dark_url,
    fttb_network_providers.logo_light_url,
    fttb_network_providers.logo_format,
    fttb_network_providers.logo_aspect_ratio,
    fttb_network_providers.active
   FROM public.fttb_network_providers
  WHERE ((fttb_network_providers.active = true) AND (fttb_network_providers.logo_url IS NOT NULL))
  ORDER BY fttb_network_providers.priority;


--
-- Name: v_recent_payment_transactions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_recent_payment_transactions WITH (security_invoker='on') AS
 SELECT pt.id,
    pt.transaction_id,
    pt.reference,
    pt.provider,
    pt.amount,
    pt.currency,
    pt.status,
    pt.payment_method,
    pt.customer_email,
    pt.customer_name,
    pt.initiated_at,
    pt.completed_at,
    pt.created_at,
    pt.customer_id
   FROM public.payment_transactions pt
  ORDER BY pt.created_at DESC
 LIMIT 100;


--
-- Name: v_subscriber_diagnostics_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_subscriber_diagnostics_summary WITH (security_invoker='on') AS
 SELECT sd.id AS diagnostics_id,
    sd.customer_service_id,
    cs.customer_id,
    concat(c.first_name, ' ', c.last_name) AS customer_name,
    c.email AS customer_email,
    c.phone AS customer_phone,
    cs.package_name,
    cs.status AS service_status,
    cs.installation_address,
    sd.health_status,
    sd.health_score,
    sd.is_session_active,
    sd.current_session_ip,
    sd.last_session_start,
    sd.last_session_duration_seconds,
    sd.total_sessions_today,
    sd.lost_carrier_count_today,
    sd.avg_session_duration_seconds,
    sd.total_sessions_7days,
    sd.lost_carrier_count_7days,
    sd.total_online_seconds_7days,
    sd.last_terminate_cause,
    sd.last_disconnect_time,
    sd.last_check_at,
    sd.last_event_at,
    sd.interstellio_subscriber_id,
    ( SELECT count(*) AS count
           FROM public.subscriber_events se
          WHERE ((se.customer_service_id = cs.id) AND (se.created_at > (now() - '24:00:00'::interval)))) AS events_24h,
    ( SELECT count(*) AS count
           FROM public.subscriber_events se
          WHERE ((se.customer_service_id = cs.id) AND ((se.severity)::text = ANY ((ARRAY['high'::character varying, 'critical'::character varying])::text[])) AND (se.created_at > (now() - '24:00:00'::interval)))) AS critical_events_24h
   FROM ((public.subscriber_diagnostics sd
     JOIN public.customer_services cs ON ((sd.customer_service_id = cs.id)))
     JOIN public.customers c ON ((cs.customer_id = c.id)))
  WHERE ((cs.status)::text = 'active'::text);


--
-- Name: v_supplier_stock_by_branch; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_supplier_stock_by_branch WITH (security_invoker='on') AS
 SELECT s.id AS supplier_id,
    s.name AS supplier_name,
    s.code AS supplier_code,
    sum(sp.stock_cpt) AS stock_cpt,
    sum(sp.stock_jhb) AS stock_jhb,
    sum(sp.stock_dbn) AS stock_dbn,
    sum(sp.stock_total) AS stock_total,
    count(sp.id) FILTER (WHERE (sp.stock_cpt > 0)) AS products_in_cpt,
    count(sp.id) FILTER (WHERE (sp.stock_jhb > 0)) AS products_in_jhb,
    count(sp.id) FILTER (WHERE (sp.stock_dbn > 0)) AS products_in_dbn
   FROM (public.suppliers s
     LEFT JOIN public.supplier_products sp ON (((s.id = sp.supplier_id) AND (sp.is_active = true))))
  GROUP BY s.id, s.name, s.code;


--
-- Name: VIEW v_supplier_stock_by_branch; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_supplier_stock_by_branch IS 'Stock levels aggregated by branch/warehouse';


--
-- Name: v_supplier_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_supplier_summary WITH (security_invoker='on') AS
 SELECT s.id,
    s.name,
    s.code,
    s.website_url,
    s.is_active,
    s.last_synced_at,
    s.sync_status,
    s.sync_error,
    count(sp.id) AS total_products,
    count(sp.id) FILTER (WHERE sp.is_active) AS active_products,
    count(sp.id) FILTER (WHERE sp.in_stock) AS in_stock_products,
    min(sp.cost_price) AS min_price,
    max(sp.cost_price) AS max_price,
    sum(sp.stock_total) AS total_stock_units
   FROM (public.suppliers s
     LEFT JOIN public.supplier_products sp ON ((s.id = sp.supplier_id)))
  GROUP BY s.id, s.name, s.code, s.website_url, s.is_active, s.last_synced_at, s.sync_status, s.sync_error;


--
-- Name: VIEW v_supplier_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_supplier_summary IS 'Supplier summary with aggregated product statistics';


--
-- Name: v_technician_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_technician_status WITH (security_invoker='on') AS
 SELECT t.id,
    t.first_name,
    t.last_name,
    ((t.first_name || ' '::text) || t.last_name) AS full_name,
    t.phone,
    t.employee_id,
    t.team,
    t.status,
    t.current_latitude,
    t.current_longitude,
    t.location_updated_at,
    t.is_active,
    cj.id AS current_job_id,
    cj.job_number AS current_job_number,
    cj.title AS current_job_title,
    cj.address AS current_job_address,
    cj.status AS current_job_status,
    ( SELECT count(*) AS count
           FROM public.field_jobs
          WHERE ((field_jobs.assigned_technician_id = t.id) AND (field_jobs.status = 'completed'::text) AND (field_jobs.completed_at >= CURRENT_DATE))) AS jobs_completed_today,
    ( SELECT count(*) AS count
           FROM public.field_jobs
          WHERE ((field_jobs.assigned_technician_id = t.id) AND (field_jobs.status = ANY (ARRAY['assigned'::text, 'en_route'::text, 'arrived'::text, 'in_progress'::text])))) AS pending_jobs
   FROM (public.technicians t
     LEFT JOIN public.field_jobs cj ON (((cj.assigned_technician_id = t.id) AND (cj.status = ANY (ARRAY['en_route'::text, 'arrived'::text, 'in_progress'::text])))))
  WHERE (t.is_active = true);


--
-- Name: v_todays_jobs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_todays_jobs WITH (security_invoker='on') AS
 SELECT j.id,
    j.job_number,
    j.order_id,
    j.customer_id,
    j.job_type,
    j.title,
    j.description,
    j.priority,
    j.address,
    j.latitude,
    j.longitude,
    j.address_notes,
    j.customer_name,
    j.customer_phone,
    j.customer_email,
    j.scheduled_date,
    j.scheduled_time_start,
    j.scheduled_time_end,
    j.estimated_duration_minutes,
    j.assigned_technician_id,
    j.assigned_at,
    j.assigned_by,
    j.status,
    j.started_at,
    j.completed_at,
    j.completion_notes,
    j.completion_photos,
    j.customer_signature_url,
    j.created_at,
    j.updated_at,
    j.created_by,
    ((t.first_name || ' '::text) || t.last_name) AS technician_name,
    t.phone AS technician_phone,
    t.current_latitude AS technician_latitude,
    t.current_longitude AS technician_longitude
   FROM (public.field_jobs j
     LEFT JOIN public.technicians t ON ((t.id = j.assigned_technician_id)))
  WHERE ((j.scheduled_date = CURRENT_DATE) OR (j.status = ANY (ARRAY['en_route'::text, 'arrived'::text, 'in_progress'::text])))
  ORDER BY j.scheduled_time_start, j.priority DESC;


--
-- Name: v_webhook_log_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_webhook_log_summary WITH (security_invoker='on') AS
 SELECT payment_webhook_logs.provider,
    payment_webhook_logs.event_type,
    payment_webhook_logs.status,
    count(*) AS total_count,
    sum(
        CASE
            WHEN (payment_webhook_logs.success = true) THEN 1
            ELSE 0
        END) AS success_count,
    sum(
        CASE
            WHEN (payment_webhook_logs.success = false) THEN 1
            ELSE 0
        END) AS failure_count,
    avg(payment_webhook_logs.processing_duration_ms) AS avg_processing_time_ms,
    max(payment_webhook_logs.received_at) AS last_received_at
   FROM public.payment_webhook_logs
  WHERE (payment_webhook_logs.received_at > (now() - '7 days'::interval))
  GROUP BY payment_webhook_logs.provider, payment_webhook_logs.event_type, payment_webhook_logs.status
  ORDER BY payment_webhook_logs.provider, payment_webhook_logs.event_type;


