--
-- Name: smb_products_complete _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.smb_products_complete WITH (security_invoker='on') AS
 SELECT p.id,
    p.package_name,
    p.package_code,
    p.speed_mbps,
    p.product_category,
    p.regular_price_zar,
    p.promo_price_zar,
    p.installation_fee_zar,
    p.total_first_month_regular_zar,
    p.total_first_month_promo_zar,
    p.selling_price_excl_vat_zar,
    p.selling_price_incl_vat_zar,
    p.total_cost_zar,
    p.gross_profit_zar,
    p.gross_margin_percentage,
    p.router_model,
    p.router_retail_price_incl_vat_zar,
    p.router_dealer_price_excl_vat_zar,
    p.router_amortised_monthly_zar,
    p.router_wifi_standard,
    p.router_ports,
    p.router_concurrent_users,
    p.router_throughput_mbps,
    p.router_features,
    p.is_active,
    p.effective_date,
    p.version,
    p.created_at,
    p.updated_at,
    COALESCE(json_agg(json_build_object('component', cc.component_name, 'category', cc.component_category, 'cost', cc.cost_amount_zar, 'provider', cc.provider, 'is_amortised', cc.is_amortised)) FILTER (WHERE (cc.id IS NOT NULL)), '[]'::json) AS cost_components,
    COALESCE(json_agg(json_build_object('feature', f.feature_name, 'category', f.feature_category, 'value', f.feature_value, 'description', f.description)) FILTER (WHERE (f.id IS NOT NULL)), '[]'::json) AS features
   FROM ((public.smb_products p
     LEFT JOIN public.smb_product_cost_components cc ON ((p.id = cc.smb_product_id)))
     LEFT JOIN public.smb_product_features f ON ((p.id = f.smb_product_id)))
  GROUP BY p.id;


--
-- Name: v_competitor_provider_stats _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.v_competitor_provider_stats WITH (security_invoker='on') AS
 SELECT p.id,
    p.name,
    p.slug,
    p.website,
    p.logo_url,
    p.provider_type,
    p.is_active,
    p.scrape_frequency,
    p.last_scraped_at,
    count(cp.id) AS total_products,
    count(
        CASE
            WHEN cp.is_current THEN 1
            ELSE NULL::integer
        END) AS current_products,
    round(avg(cp.monthly_price), 2) AS avg_monthly_price,
    min(cp.monthly_price) AS min_monthly_price,
    max(cp.monthly_price) AS max_monthly_price,
    count(DISTINCT pcm.id) AS matched_products
   FROM ((public.competitor_providers p
     LEFT JOIN public.competitor_products cp ON ((p.id = cp.provider_id)))
     LEFT JOIN public.product_competitor_matches pcm ON ((cp.id = pcm.competitor_product_id)))
  GROUP BY p.id;


