--

CREATE POLICY partners_add_activities ON public.partner_lead_activities FOR INSERT WITH CHECK (((partner_id IN ( SELECT partners.id
   FROM public.partners
  WHERE (partners.user_id = auth.uid()))) AND (lead_id IN ( SELECT coverage_leads.id
   FROM public.coverage_leads
  WHERE (coverage_leads.assigned_partner_id = partner_lead_activities.partner_id)))));


